import React from "react";
import { View, StyleSheet, Pressable, Platform } from "react-native";
import { Feather } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";
import { BlurView } from "expo-blur";
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
} from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { Spacing, BorderRadius, CyclePhase, PhaseGradients } from "@/constants/theme";

interface InsightCardProps {
  phase: CyclePhase;
  tip: string;
  icon?: keyof typeof Feather.glyphMap;
  title?: string;
  onPress?: () => void;
}

const PHASE_ICONS: Record<CyclePhase, keyof typeof Feather.glyphMap> = {
  menstrual: "heart",
  follicular: "sun",
  ovulation: "star",
  luteal: "moon",
};

const AnimatedPressable = Animated.createAnimatedComponent(Pressable);

export function InsightCard({ phase, tip, icon, title, onPress }: InsightCardProps) {
  const scale = useSharedValue(1);
  const phaseGradient = PhaseGradients[phase];
  const gradientColors = phaseGradient.colors as [string, string];
  const iconName = icon || PHASE_ICONS[phase];
  const displayTitle = title || "DAILY INSIGHT";

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  const handlePressIn = () => {
    scale.value = withSpring(0.98, { damping: 15, stiffness: 150 });
  };

  const handlePressOut = () => {
    scale.value = withSpring(1, { damping: 15, stiffness: 150 });
  };

  return (
    <AnimatedPressable
      onPress={onPress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      style={animatedStyle}
    >
      <LinearGradient
        colors={gradientColors}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 0 }}
        style={styles.card}
      >
        <View style={styles.iconBubble}>
          {Platform.OS !== "web" ? (
            <BlurView intensity={10} style={StyleSheet.absoluteFill} />
          ) : null}
          <Feather name={iconName} size={16} color="#FFFFFF" />
        </View>
        <ThemedText style={styles.title}>
          {displayTitle}
        </ThemedText>
        <ThemedText style={styles.body}>
          {tip}
        </ThemedText>
      </LinearGradient>
    </AnimatedPressable>
  );
}

const styles = StyleSheet.create({
  card: {
    padding: Spacing.lg,
    borderRadius: BorderRadius.md,
    overflow: "hidden",
  },
  iconBubble: {
    width: 32,
    height: 32,
    borderRadius: BorderRadius.full,
    backgroundColor: "rgba(255,255,255,0.2)",
    alignItems: "center",
    justifyContent: "center",
    marginBottom: Spacing.md,
    overflow: "hidden",
  },
  title: {
    fontSize: 14,
    fontWeight: "700",
    color: "rgba(255,255,255,0.9)",
    marginBottom: Spacing.xs,
  },
  body: {
    fontSize: 12,
    fontWeight: "500",
    color: "rgba(255,255,255,0.8)",
    lineHeight: 18,
  },
});

components/PhaseChip.tsx.content:
import React from "react";
import { View, StyleSheet } from "react-native";
import { Feather } from "@expo/vector-icons";

import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius, CyclePhase } from "@/constants/theme";
import { getPhaseName, getPhaseIcon } from "@/services/cycleService";

interface PhaseChipProps {
  phase: CyclePhase;
  size?: "small" | "medium";
}

export function PhaseChip({ phase, size = "medium" }: PhaseChipProps) {
  const { getPhaseColors } = useTheme();
  const phaseColors = getPhaseColors(phase);
  const iconName = getPhaseIcon(phase) as React.ComponentProps<typeof Feather>["name"];

  const isSmall = size === "small";

  return (
    <View
      style={[
        styles.chip,
        {
          backgroundColor: phaseColors.background,
          paddingVertical: isSmall ? Spacing.xs : Spacing.sm,
          paddingHorizontal: isSmall ? Spacing.sm : Spacing.md,
        },
      ]}
    >
      <Feather
        name={iconName}
        size={isSmall ? 12 : 14}
        color={phaseColors.primary}
        style={styles.icon}
      />
      <ThemedText
        type="chip"
        style={[styles.label, { color: phaseColors.primary }]}
      >
        {getPhaseName(phase).toUpperCase()}
      </ThemedText>
    </View>
  );
}

const styles = StyleSheet.create({
  chip: {
    flexDirection: "row",
    alignItems: "center",
    borderRadius: BorderRadius.full,
  },
  icon: {
    marginRight: Spacing.xs,
  },
  label: {
    fontWeight: "700",
  },
});

hooks/useColorScheme.web.ts.content:
import { useEffect, useState } from "react";
import { useColorScheme as useRNColorScheme } from "react-native";

/**
 * To support static rendering, this value needs to be re-calculated on the client side for web
 */
export function useColorScheme() {
  const [hasHydrated, setHasHydrated] = useState(false);

  useEffect(() => {
    setHasHydrated(true);
  }, []);

  const colorScheme = useRNColorScheme();

  if (hasHydrated) {
    return colorScheme;
  }

  return "light";
}

