import React, { createContext, useContext, useState, useEffect, ReactNode } from "react";
import { storage, User, CycleConfig, isSuperAdmin, SUPER_ADMIN_EMAIL } from "@/services/storage";
import { authApi, setAuthToken, clearAuthToken, checkApiHealth } from "@/services/api";

export type UserRole = "user" | "merchant" | "admin";

interface AuthContextType {
  user: User | null;
  cycleConfig: CycleConfig | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  isOnline: boolean;
  login: (email: string, password: string) => Promise<{ success: boolean; error?: string }>;
  register: (email: string, name: string, password: string, language?: string) => Promise<{ success: boolean; error?: string }>;
  logout: () => Promise<void>;
  updateCycleConfig: (config: CycleConfig) => Promise<void>;
  updateUser: (updates: Partial<User>) => Promise<void>;
  updateProfile: (data: {
    name?: string;
    phone?: string;
    language?: string;
    cycleConfig?: { lastPeriodDate?: string; cycleLength?: number; periodLength?: number };
    address?: { addressLine1?: string; city?: string; district?: string; latitude?: number; longitude?: number };
  }) => Promise<{ success: boolean; error?: string }>;
  updateAvatar: (uri: string) => Promise<void>;
  deleteAccount: () => Promise<{ success: boolean; error?: string }>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [cycleConfig, setCycleConfig] = useState<CycleConfig | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isOnline, setIsOnline] = useState(true);

  useEffect(() => {
    loadUser();
    checkOnlineStatus();
  }, []);

  const checkOnlineStatus = async () => {
    const online = await checkApiHealth();
    setIsOnline(online);
  };

  const loadUser = async () => {
    try {
      const savedUser = await storage.getUser();
      const savedConfig = await storage.getCycleConfig();

      if (savedUser) {
        setUser(savedUser as User);
        setCycleConfig(savedConfig);

        const { data, error } = await authApi.getMe();
        if (data?.user) {
          const apiUser: User = {
            id: data.user.id,
            email: data.user.email,
            name: data.user.name,
            role: data.user.role.toLowerCase() as UserRole,
            phone: data.user.phone,
            avatar: data.user.avatarUrl,
            language: data.user.language,
            createdAt: data.user.createdAt,
            merchantId: data.user.merchant?.id,
            merchantStatus: data.user.merchant?.status,
            isSuperAdmin: isSuperAdmin(data.user.email),
          };

          setUser(apiUser);
          await storage.setUser(apiUser);

          if (data.user.profile?.lastPeriodDate) {
            const serverConfig: CycleConfig = {
              lastPeriodDate: data.user.profile.lastPeriodDate,
              cycleLength: data.user.profile.cycleLength || 28,
              periodLength: data.user.profile.periodLength || 5,
            };
            setCycleConfig(serverConfig);
            await storage.setCycleConfig(serverConfig);
          }
          setIsOnline(true);
        } else if (error) {
          if (error.includes("401") || error.includes("Unauthorized")) {
            await clearAuthToken();
            await storage.removeUser();
            setUser(null);
          }
          setIsOnline(false);
        }
      }
    } catch (error) {
      console.error("Error loading user:", error);
      setIsOnline(false);
    } finally {
      setIsLoading(false);
    }
  };

  const register = async (email: string, name: string, password: string, language?: string): Promise<{ success: boolean; error?: string }> => {
    try {
      const { data, error } = await authApi.register(email, name, password, language);

      if (error) {
        return { success: false, error };
      }

      if (data) {
        await setAuthToken(data.token);

        const newUser: User = {
          id: data.user.id,
          email: data.user.email,
          name: data.user.name,
          role: data.user.role.toLowerCase() as UserRole,
          language: data.user.language,
          createdAt: new Date().toISOString(),
          isSuperAdmin: isSuperAdmin(data.user.email),
        };

        await storage.setUser(newUser);
        setUser(newUser);

        const defaultConfig: CycleConfig = {
          lastPeriodDate: new Date().toISOString(),
          cycleLength: 28,
          periodLength: 5,
        };
        await storage.setCycleConfig(defaultConfig);
        setCycleConfig(defaultConfig);
        setIsOnline(true);

        return { success: true };
      }

      return { success: false, error: "Unknown error" };
    } catch (error: any) {
      return { success: false, error: error.message || "Registration failed" };
    }
  };

  const login = async (email: string, name: string): Promise<{ success: boolean; error?: string }> => {
    try {
      const apiAvailable = await checkApiHealth();

      if (apiAvailable) {
        const { data, error } = await authApi.login(email, name);

        if (error) {
          return { success: false, error };
        }

        if (data) {
          await setAuthToken(data.token);

          const loggedInUser: User = {
            id: data.user.id,
            email: data.user.email,
            name: data.user.name,
            role: data.user.role.toLowerCase() as UserRole,
            language: data.user.language,
            createdAt: new Date().toISOString(),
            isSuperAdmin: isSuperAdmin(data.user.email),
          };

          await storage.setUser(loggedInUser);
          setUser(loggedInUser);

          const existingConfig = await storage.getCycleConfig();
          if (!existingConfig) {
            const defaultConfig: CycleConfig = {
              lastPeriodDate: new Date().toISOString(),
              cycleLength: 28,
              periodLength: 5,
            };
            await storage.setCycleConfig(defaultConfig);
            setCycleConfig(defaultConfig);
          }

          setIsOnline(true);
          return { success: true };
        }

        return { success: false, error: "Unknown error" };
      } else {
        let role: UserRole = "user";
        const isSuper = isSuperAdmin(email);
        if (isSuper || email.toLowerCase() === "admin@jasmin.app") {
          role = "admin";
        } else if (email.toLowerCase().includes("merchant@") || email.toLowerCase().includes("seller@")) {
          role = "merchant";
        }

        const offlineUser: User = {
          id: `offline_${Date.now()}`,
          email: email,
          name: name,
          role: role,
          createdAt: new Date().toISOString(),
          isSuperAdmin: isSuper,
        };

        await storage.setUser(offlineUser);
        setUser(offlineUser);

        const existingConfig = await storage.getCycleConfig();
        if (!existingConfig) {
          const defaultConfig: CycleConfig = {
            lastPeriodDate: new Date().toISOString(),
            cycleLength: 28,
            periodLength: 5,
          };
          await storage.setCycleConfig(defaultConfig);
          setCycleConfig(defaultConfig);
        }

        setIsOnline(false);
        return { success: true };
      }
    } catch (error: any) {
      let role: UserRole = "user";
      const isSuper = isSuperAdmin(email);
      if (isSuper || email.toLowerCase() === "admin@jasmin.app") {
        role = "admin";
      } else if (email.toLowerCase().includes("merchant@") || email.toLowerCase().includes("seller@")) {
        role = "merchant";
      }

      const offlineUser: User = {
        id: `offline_${Date.now()}`,
        email: email,
        name: name,
        role: role,
        createdAt: new Date().toISOString(),
        isSuperAdmin: isSuper,
      };

      await storage.setUser(offlineUser);
      setUser(offlineUser);

      const existingConfig = await storage.getCycleConfig();
      if (!existingConfig) {
        const defaultConfig: CycleConfig = {
          lastPeriodDate: new Date().toISOString(),
          cycleLength: 28,
          periodLength: 5,
        };
        await storage.setCycleConfig(defaultConfig);
        setCycleConfig(defaultConfig);
      }

      setIsOnline(false);
      return { success: true };
    }
  };

  const logout = async () => {
    await clearAuthToken();
    await storage.removeUser();
    setUser(null);
  };

  const updateCycleConfig = async (config: CycleConfig) => {
    await storage.setCycleConfig(config);
    setCycleConfig(config);

    if (isOnline) {
      await authApi.updateProfile({
        cycleConfig: {
          lastPeriodDate: config.lastPeriodDate,
          cycleLength: config.cycleLength,
          periodLength: config.periodLength,
        },
      });
    }
  };

  const updateUser = async (updates: Partial<User>) => {
    if (user) {
      const updatedUser = { ...user, ...updates };
      await storage.setUser(updatedUser);
      setUser(updatedUser);
    }
  };

  const updateProfile = async (data: {
    name?: string;
    phone?: string;
    language?: string;
    cycleConfig?: { lastPeriodDate?: string; cycleLength?: number; periodLength?: number };
    address?: { addressLine1?: string; city?: string; district?: string; latitude?: number; longitude?: number };
  }): Promise<{ success: boolean; error?: string }> => {
    try {
      const { error } = await authApi.updateProfile(data);

      if (error) {
        return { success: false, error };
      }

      if (user) {
        const updatedUser = {
          ...user,
          name: data.name || user.name,
          phone: data.phone || user.phone,
          language: data.language || user.language,
        };
        await storage.setUser(updatedUser);
        setUser(updatedUser);
      }

      if (data.cycleConfig) {
        const updatedConfig: CycleConfig = {
          lastPeriodDate: data.cycleConfig.lastPeriodDate || cycleConfig?.lastPeriodDate || new Date().toISOString(),
          cycleLength: data.cycleConfig.cycleLength || cycleConfig?.cycleLength || 28,
          periodLength: data.cycleConfig.periodLength || cycleConfig?.periodLength || 5,
        };
        await storage.setCycleConfig(updatedConfig);
        setCycleConfig(updatedConfig);
      }

      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Update failed" };
    }
  };

  const updateAvatar = async (uri: string) => {
    if (user) {
      const updatedUser = { ...user, avatar: uri };
      await storage.setUser(updatedUser);
      setUser(updatedUser);
    }
  };

  const deleteAccount = async (): Promise<{ success: boolean; error?: string }> => {
    try {
      const { error } = await authApi.deleteAccount();

      if (error) {
        return { success: false, error };
      }

      await logout();
      return { success: true };
    } catch (error: any) {
      return { success: false, error: error.message || "Delete failed" };
    }
  };

  const refreshUser = async () => {
    await loadUser();
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        cycleConfig,
        isLoading,
        isAuthenticated: !!user,
        isOnline,
        login,
        register,
        logout,
        updateCycleConfig,
        updateUser,
        updateProfile,
        updateAvatar,
        deleteAccount,
        refreshUser,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

