                {merchantProducts.length}
              </ThemedText>
              <ThemedText type="small" style={styles.statLabel}>
                Products
              </ThemedText>
            </View>
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          AVAILABLE PRODUCTS
        </ThemedText>
        {merchantProducts.map((product, index) => (
          <View key={product.id} style={styles.productRow}>
            <View style={styles.productCardWrapper}>
              <ProductCard
                product={product}
                onPress={() => navigation.navigate("ProductDetail", { productId: product.id })}
                index={index}
              />
            </View>
            <Pressable
              onPress={() => addToCart(product)}
              style={({ pressed }) => [
                styles.addButton,
                {
                  backgroundColor: isDark
                    ? JasminColors.night.surface
                    : JasminColors.brand.pink50,
                  opacity: pressed ? 0.7 : 1,
                  transform: [{ scale: pressed ? 0.9 : 1 }],
                },
              ]}
            >
              <Feather name="plus" size={20} color={JasminColors.brand.pink500} />
            </Pressable>
          </View>
        ))}
      </Animated.View>

      {cartItems.length > 0 && (
        <Animated.View
          entering={FadeInDown.duration(300)}
          style={[
            styles.cartBar,
            { backgroundColor: isDark ? JasminColors.night.surface : "#FFFFFF" },
          ]}
        >
          <View style={styles.cartInfo}>
            <View style={styles.cartBadge}>
              <ThemedText type="chip" style={styles.cartCount}>
                {cartItems.reduce((sum, item) => sum + item.quantity, 0)}
              </ThemedText>
            </View>
            <View>
              <ThemedText type="small" style={{ color: theme.textMuted }}>
                Cart Total
              </ThemedText>
              <ThemedText type="h4" style={{ color: JasminColors.brand.pink500 }}>
                {formatRWF(cartTotal * 1200)}
              </ThemedText>
            </View>
          </View>
          <View style={styles.cartActions}>
            <Pressable
              onPress={handleReserve}
              style={[
                styles.cartButton,
