import React, { useState, useEffect } from "react";
import { StyleSheet, View } from "react-native";
import { NavigationContainer } from "@react-navigation/native";
import { GestureHandlerRootView } from "react-native-gesture-handler";
import { KeyboardProvider } from "react-native-keyboard-controller";
import { SafeAreaProvider } from "react-native-safe-area-context";
import { StatusBar } from "expo-status-bar";
import Animated, { FadeIn, FadeOut } from "react-native-reanimated";

import MainTabNavigator from "@/navigation/MainTabNavigator";
import MerchantTabNavigator from "@/navigation/MerchantTabNavigator";
import AdminTabNavigator from "@/navigation/AdminTabNavigator";
import AuthNavigator from "@/navigation/AuthNavigator";
import { ErrorBoundary } from "@/components/ErrorBoundary";
import { BrandedSplashScreen } from "@/components/BrandedSplashScreen";
import { AuthProvider, useAuth } from "@/context/AuthContext";
import { LanguageProvider } from "@/context/LanguageContext";
import { DiscreetModeProvider } from "@/context/DiscreetModeContext";
import { JasminColors } from "@/constants/theme";

function getNavigatorForRole(role: string | undefined) {
  switch (role) {
    case "merchant":
      return <MerchantTabNavigator />;
    case "admin":
      return <AdminTabNavigator />;
    case "user":
    default:
      return <MainTabNavigator />;
  }
}

function AppContent() {
  const { isLoading, isAuthenticated, user } = useAuth();
  const [showSplash, setShowSplash] = useState(true);

  const handleSplashComplete = () => {
    setShowSplash(false);
  };

  if (isLoading || showSplash) {
    return <BrandedSplashScreen onAnimationComplete={handleSplashComplete} />;
  }

  return (
    <NavigationContainer>
      {isAuthenticated ? getNavigatorForRole(user?.role) : <AuthNavigator />}
    </NavigationContainer>
  );
}

export default function App() {
  return (
    <ErrorBoundary>
      <SafeAreaProvider>
        <GestureHandlerRootView style={styles.root}>
          <KeyboardProvider>
            <LanguageProvider>
              <DiscreetModeProvider>
                <AuthProvider>
                  <AppContent />
                </AuthProvider>
              </DiscreetModeProvider>
            </LanguageProvider>
            <StatusBar style="auto" />
          </KeyboardProvider>
        </GestureHandlerRootView>
      </SafeAreaProvider>
    </ErrorBoundary>
  );
}

const styles = StyleSheet.create({
  root: {
    flex: 1,
  },
});

