              "{dailyInspiration.quote}"
            </ThemedText>
          </View>
          <ThemedText style={styles.inspirationAuthor}>
            - {dailyInspiration.author}
          </ThemedText>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(400).duration(500)}>
