            isDark={isDark}
          />
          <QuickAction
            icon="settings"
            label="Settings"
            onPress={() => navigation.navigate("ProfileTab", { screen: "Settings" })}
            isDark={isDark}
          />
        </View>
      </Animated.View>

      <Animated.View
        entering={FadeInUp.delay(500).duration(300)}
        style={[
          styles.fabContainer,
          { bottom: insets.bottom + 100 },
        ]}
      >
        <Pressable
          onPress={() => setShowAIChat(true)}
          style={({ pressed }) => [
            styles.fab,
            { transform: [{ scale: pressed ? 0.95 : 1 }] },
          ]}
        >
          <LinearGradient
            colors={[JasminColors.brand.purple500, JasminColors.brand.purple600]}
            style={styles.fabGradient}
          >
