import React, { useState, useEffect } from "react";
import { View, StyleSheet, Pressable, Alert, TextInput } from "react-native";
import { Feather } from "@expo/vector-icons";
import Animated, { FadeInDown, Layout } from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { ScreenKeyboardAwareScrollView } from "@/components/ScreenKeyboardAwareScrollView";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import { storage, DependentProfile } from "@/services/storage";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

export default function ManageProfilesScreen() {
  const { theme, isDark } = useTheme();
  const { user } = useAuth();

  const [profiles, setProfiles] = useState<DependentProfile[]>([]);
  const [activeProfileId, setActiveProfileId] = useState<string | null>(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [newProfileName, setNewProfileName] = useState("");
  const [newProfileRelation, setNewProfileRelation] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    loadProfiles();
  }, []);

  const loadProfiles = async () => {
    const savedProfiles = await storage.getDependentProfiles();
    const activeId = await storage.getActiveProfileId();
    setProfiles(savedProfiles);
    setActiveProfileId(activeId);
  };

  const handleAddProfile = async () => {
    if (!newProfileName.trim()) {
      Alert.alert("Missing Name", "Please enter a name for the profile.");
      return;
    }

    setIsLoading(true);
    try {
      const newProfile: DependentProfile = {
        id: Date.now().toString(),
        name: newProfileName.trim(),
        relation: newProfileRelation.trim() || "Dependent",
        createdAt: new Date().toISOString(),
      };

      await storage.addDependentProfile(newProfile);
      setProfiles([...profiles, newProfile]);
      setNewProfileName("");
      setNewProfileRelation("");
      setShowAddForm(false);
      Alert.alert("Profile Added", `${newProfile.name} has been added.`);
    } catch (error) {
      Alert.alert("Error", "Failed to add profile. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSetActive = async (profileId: string | null) => {
    await storage.setActiveProfileId(profileId);
    setActiveProfileId(profileId);

    const profileName = profileId 
      ? profiles.find(p => p.id === profileId)?.name || "Profile"
      : user?.name || "You";

    Alert.alert("Profile Switched", `Now tracking cycle for ${profileName}.`);
  };

  const handleDeleteProfile = (profile: DependentProfile) => {
    Alert.alert(
      "Delete Profile",
      `Are you sure you want to delete ${profile.name}'s profile? This will remove all their cycle data.`,
      [
        { text: "Cancel", style: "cancel" },
        {
          text: "Delete",
          style: "destructive",
          onPress: async () => {
            await storage.removeDependentProfile(profile.id);
            if (activeProfileId === profile.id) {
              await storage.setActiveProfileId(null);
              setActiveProfileId(null);
            }
            setProfiles(profiles.filter(p => p.id !== profile.id));
          },
        },
      ]
    );
  };

  return (
    <ScreenKeyboardAwareScrollView>
      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <GlassCard style={styles.infoCard}>
          <Feather
            name="users"
            size={24}
            color={JasminColors.brand.purple500}
          />
          <ThemedText type="body" style={styles.infoText}>
            Manage cycle tracking for yourself and your dependents. Switch between profiles to track different cycles.
          </ThemedText>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          YOUR PROFILE
        </ThemedText>
        <Pressable
          onPress={() => handleSetActive(null)}
          style={({ pressed }) => [
            styles.profileCard,
            {
              backgroundColor: isDark
                ? JasminColors.night.surface
                : "#FFFFFF",
              borderColor: activeProfileId === null
                ? JasminColors.brand.pink500
                : "transparent",
              borderWidth: 2,
              opacity: pressed ? 0.9 : 1,
            },
          ]}
        >
          <View
            style={[
              styles.avatar,
              {
                backgroundColor: isDark
                  ? JasminColors.night.deep
                  : JasminColors.brand.pink100,
              },
            ]}
          >
            <ThemedText type="h4" style={styles.avatarText}>
              {user?.name?.charAt(0).toUpperCase() || "Y"}
            </ThemedText>
          </View>
          <View style={styles.profileInfo}>
            <ThemedText type="body" style={styles.profileName}>
              {user?.name || "You"}
            </ThemedText>
            <ThemedText type="small" style={styles.profileRelation}>
              Primary Account
            </ThemedText>
          </View>
          {activeProfileId === null ? (
            <View style={styles.activeBadge}>
              <Feather name="check" size={14} color="#FFFFFF" />
              <ThemedText type="small" style={styles.activeBadgeText}>
                Active
              </ThemedText>
            </View>
          ) : null}
        </Pressable>
      </Animated.View>

      {profiles.length > 0 ? (
        <Animated.View entering={FadeInDown.delay(300).duration(500)}>
          <ThemedText type="sectionHeader" style={styles.sectionLabel}>
            DEPENDENTS
          </ThemedText>
          {profiles.map((profile, index) => (
            <Animated.View
              key={profile.id}
              entering={FadeInDown.delay(index * 75).duration(400)}
              layout={Layout.springify()}
            >
              <Pressable
                onPress={() => handleSetActive(profile.id)}
                style={({ pressed }) => [
                  styles.profileCard,
                  {
                    backgroundColor: isDark
                      ? JasminColors.night.surface
                      : "#FFFFFF",
                    borderColor: activeProfileId === profile.id
                      ? JasminColors.brand.pink500
                      : "transparent",
                    borderWidth: 2,
                    opacity: pressed ? 0.9 : 1,
                  },
                ]}
              >
                <View
                  style={[
                    styles.avatar,
                    {
                      backgroundColor: isDark
                        ? JasminColors.night.deep
                        : JasminColors.brand.purple100,
                    },
                  ]}
                >
                  <ThemedText type="h4" style={styles.avatarText}>
                    {profile.name.charAt(0).toUpperCase()}
                  </ThemedText>
                </View>
                <View style={styles.profileInfo}>
                  <ThemedText type="body" style={styles.profileName}>
                    {profile.name}
                  </ThemedText>
                  <ThemedText type="small" style={styles.profileRelation}>
                    {profile.relation}
                  </ThemedText>
                </View>
                {activeProfileId === profile.id ? (
                  <View style={styles.activeBadge}>
                    <Feather name="check" size={14} color="#FFFFFF" />
                    <ThemedText type="small" style={styles.activeBadgeText}>
                      Active
                    </ThemedText>
                  </View>
                ) : (
                  <Pressable
                    onPress={() => handleDeleteProfile(profile)}
                    style={styles.deleteButton}
                  >
                    <Feather
                      name="trash-2"
                      size={18}
                      color={JasminColors.functional.danger}
                    />
                  </Pressable>
                )}
              </Pressable>
            </Animated.View>
          ))}
        </Animated.View>
      ) : null}

      <Animated.View entering={FadeInDown.delay(400).duration(500)}>
        {showAddForm ? (
          <GlassCard style={styles.addForm}>
            <ThemedText type="h4" style={styles.formTitle}>
              Add New Profile
            </ThemedText>

            <View style={styles.inputGroup}>
              <ThemedText type="small" style={styles.label}>
                Name
              </ThemedText>
              <TextInput
                style={[
                  styles.input,
                  {
                    backgroundColor: isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[50],
                    color: theme.text,
                  },
                ]}
                value={newProfileName}
                onChangeText={setNewProfileName}
                placeholder="Enter name"
                placeholderTextColor={theme.placeholder}
              />
            </View>

            <View style={styles.inputGroup}>
              <ThemedText type="small" style={styles.label}>
                Relationship (Optional)
              </ThemedText>
              <TextInput
                style={[
                  styles.input,
                  {
                    backgroundColor: isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[50],
                    color: theme.text,
                  },
                ]}
                value={newProfileRelation}
                onChangeText={setNewProfileRelation}
                placeholder="e.g., Daughter, Sister"
                placeholderTextColor={theme.placeholder}
              />
            </View>

            <View style={styles.formButtons}>
              <Button
                variant="secondary"
                onPress={() => {
                  setShowAddForm(false);
                  setNewProfileName("");
                  setNewProfileRelation("");
                }}
                style={styles.formButton}
              >
                Cancel
              </Button>
              <Button
                onPress={handleAddProfile}
                disabled={isLoading}
                style={styles.formButton}
              >
                {isLoading ? "Adding..." : "Add Profile"}
              </Button>
            </View>
          </GlassCard>
        ) : (
          <Button
            variant="outline"
            onPress={() => setShowAddForm(true)}
            style={styles.addButton}
          >
            <View style={styles.addButtonContent}>
              <Feather name="plus" size={20} color={theme.link} />
              <ThemedText type="body" style={[styles.addButtonText, { color: theme.link }]}>
                Add Dependent Profile
              </ThemedText>
            </View>
          </Button>
        )}
      </Animated.View>
    </ScreenKeyboardAwareScrollView>
  );
}

