import React, { useState, useMemo, useCallback } from "react";
import { View, StyleSheet } from "react-native";
import { useNavigation } from "@react-navigation/native";
import { Feather } from "@expo/vector-icons";
import Animated, { FadeInDown } from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { GlassCard } from "@/components/GlassCard";
import { CycleWheel } from "@/components/CycleWheel";
import { CycleCalendar } from "@/components/CycleCalendar";
import { PhaseChip } from "@/components/PhaseChip";
import { InsightCard } from "@/components/InsightCard";
import { QuickLog, SymptomType } from "@/components/QuickLog";
import { Button } from "@/components/Button";
import { JasminBrandIcon } from "@/components/JasminBrandIcon";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import {
  calculateCycleInfo,
  getPhaseDescription,
  getPhaseForDay,
} from "@/services/cycleService";
import { Spacing, BorderRadius, CyclePhase, JasminColors } from "@/constants/theme";

const PHASE_INSIGHTS: Record<CyclePhase, string> = {
  menstrual: "Rest and gentle movement can help with comfort today.",
  follicular: "Energy is rising - great time for new projects!",
  ovulation: "Peak fertility and energy. You may feel more social.",
  luteal: "Focus on self-care as your body prepares for a new cycle.",
};

export default function CycleScreen() {
  const navigation = useNavigation<any>();
  const { theme, isDark } = useTheme();
  const { cycleConfig } = useAuth();

  const cycleInfo = useMemo(() => calculateCycleInfo(cycleConfig), [cycleConfig]);

  const cycleStartDate = useMemo(() => {
    if (!cycleConfig?.lastPeriodDate) return new Date();
    return new Date(cycleConfig.lastPeriodDate);
  }, [cycleConfig]);

  const totalDays = cycleConfig?.cycleLength || 28;
  const periodLength = cycleConfig?.periodLength || 5;

  const [selectedDay, setSelectedDay] = useState<number | null>(cycleInfo.hasData ? cycleInfo.currentDay : null);
  const [loggedDays, setLoggedDays] = useState<number[]>([]);

  const selectedDayPhase = useMemo(() => {
    if (selectedDay === null) return cycleInfo.phase;
    return getPhaseForDay(selectedDay, totalDays, periodLength);
  }, [selectedDay, totalDays, periodLength, cycleInfo.phase]);

  const handleDaySelect = useCallback((day: number) => {
    setSelectedDay(day);
  }, []);

  const handleLogSymptom = useCallback((symptom: SymptomType) => {
    if (selectedDay !== null && !loggedDays.includes(selectedDay)) {
      setLoggedDays((prev) => [...prev, selectedDay]);
    }
  }, [selectedDay, loggedDays]);

  if (!cycleInfo.hasData) {
    return (
      <ScreenScrollView>
        <Animated.View entering={FadeInDown.delay(100).duration(500)}>
          <GlassCard style={styles.emptyCard}>
            <View style={styles.emptyIconContainer}>
              <JasminBrandIcon size={80} showBackground />
            </View>

            <ThemedText type="h3" style={styles.emptyTitle}>
              Start Tracking Your Cycle
            </ThemedText>

            <ThemedText type="body" style={styles.emptyDescription}>
              Set up your cycle information to get personalized insights, predictions, and wellness recommendations tailored to you.
            </ThemedText>

            <View style={styles.featureList}>
              <View style={styles.featureItem}>
                <View style={[styles.featureIcon, { backgroundColor: JasminColors.brand.pink100 }]}>
                  <Feather name="calendar" size={20} color={JasminColors.brand.pink500} />
                </View>
                <ThemedText type="body" style={styles.featureText}>
                  Track your period and fertile days
                </ThemedText>
              </View>

              <View style={styles.featureItem}>
                <View style={[styles.featureIcon, { backgroundColor: JasminColors.brand.purple100 }]}>
                  <Feather name="zap" size={20} color={JasminColors.brand.purple600} />
                </View>
                <ThemedText type="body" style={styles.featureText}>
                  Get phase-specific wellness tips
                </ThemedText>
              </View>

              <View style={styles.featureItem}>
                <View style={[styles.featureIcon, { backgroundColor: JasminColors.brand.teal50 }]}>
                  <Feather name="heart" size={20} color={JasminColors.brand.teal600} />
                </View>
                <ThemedText type="body" style={styles.featureText}>
                  Log symptoms and moods daily
                </ThemedText>
              </View>
            </View>

            <Button
              onPress={() => navigation.navigate("ProfileStack", { screen: "Settings" })}
              style={styles.setupButton}
            >
              Set Up My Cycle
            </Button>
          </GlassCard>
        </Animated.View>

        <Animated.View entering={FadeInDown.delay(200).duration(500)}>
          <GlassCard style={styles.privacyNote}>
            <Feather name="shield" size={20} color={JasminColors.brand.teal600} />
            <ThemedText type="small" style={styles.privacyText}>
              Your data stays private and secure. Only you can see your cycle information.
            </ThemedText>
          </GlassCard>
        </Animated.View>
      </ScreenScrollView>
    );
  }

  return (
    <ScreenScrollView>
      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <GlassCard style={styles.mainCard}>
          <View style={styles.wheelSection}>
            <CycleWheel
              currentDay={cycleInfo.currentDay}
              totalDays={totalDays}
              phase={cycleInfo.phase}
            />
          </View>

          <View style={styles.phaseSection}>
            <PhaseChip phase={cycleInfo.phase} />
            <ThemedText type="body" style={styles.phaseDesc}>
              {getPhaseDescription(cycleInfo.phase)}
            </ThemedText>
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(150).duration(500)}>
        <InsightCard
          phase={cycleInfo.phase}
          tip={PHASE_INSIGHTS[cycleInfo.phase]}
        />
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)} style={styles.quickLogSection}>
        <QuickLog
          selectedDay={selectedDay || cycleInfo.currentDay}
          phase={selectedDayPhase}
          onLogSymptom={handleLogSymptom}
        />
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(250).duration(500)} style={styles.calendarSection}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          CALENDAR
        </ThemedText>
        <CycleCalendar
          currentDay={cycleInfo.currentDay}
          totalDays={totalDays}
          periodLength={periodLength}
          cycleStartDate={cycleStartDate}
          selectedDay={selectedDay}
          onDaySelect={handleDaySelect}
          loggedDays={loggedDays}
        />
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(300).duration(500)}>
        <Button
          onPress={() => navigation.navigate("Journal")}
          style={styles.journalButton}
        >
          Add Journal Entry
        </Button>
      </Animated.View>
    </ScreenScrollView>
  );
}

const styles = StyleSheet.create({
  mainCard: {
    marginBottom: Spacing.xl,
  },
  wheelSection: {
    alignItems: "center",
    paddingVertical: Spacing.lg,
  },
  phaseSection: {
    alignItems: "center",
    paddingTop: Spacing.lg,
    borderTopWidth: StyleSheet.hairlineWidth,
    borderTopColor: "rgba(0,0,0,0.1)",
  },
  phaseDesc: {
    textAlign: "center",
    marginTop: Spacing.md,
    paddingHorizontal: Spacing.lg,
    opacity: 0.7,
  },
  sectionLabel: {
    marginBottom: Spacing.md,
  },
  quickLogSection: {
    marginTop: Spacing.xl,
  },
  calendarSection: {
    marginTop: Spacing.xl,
  },
  journalButton: {
    marginTop: Spacing.xl,
    marginBottom: Spacing.xl,
  },
  emptyCard: {
    alignItems: "center",
    paddingVertical: Spacing.xl * 2,
    paddingHorizontal: Spacing.xl,
  },
  emptyIconContainer: {
    marginBottom: Spacing.xl,
  },
  emptyTitle: {
    textAlign: "center",
    marginBottom: Spacing.md,
  },
  emptyDescription: {
    textAlign: "center",
    opacity: 0.7,
    marginBottom: Spacing.xl,
    lineHeight: 22,
  },
  featureList: {
    width: "100%",
    marginBottom: Spacing.xl,
  },
  featureItem: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: Spacing.md,
  },
  featureIcon: {
    width: 40,
    height: 40,
    borderRadius: BorderRadius.sm,
    alignItems: "center",
    justifyContent: "center",
    marginRight: Spacing.md,
  },
  featureText: {
    flex: 1,
    opacity: 0.8,
  },
  setupButton: {
    width: "100%",
  },
  privacyNote: {
    flexDirection: "row",
    alignItems: "center",
    paddingVertical: Spacing.md,
    paddingHorizontal: Spacing.lg,
    marginTop: Spacing.xl,
  },
  privacyText: {
