  badgeColor?: string;
  isDark: boolean;
  textMuted: string;
}

function MenuItem({
  icon,
  label,
  onPress,
  showBadge,
  badgeColor,
  isDark,
  textMuted,
}: MenuItemProps) {
  return (
    <Pressable
      onPress={onPress}
      style={({ pressed }) => [
        styles.menuItem,
        {
          backgroundColor: pressed
            ? isDark
              ? "rgba(255,255,255,0.05)"
              : "rgba(0,0,0,0.03)"
            : "transparent",
        },
      ]}
    >
      <View
        style={[
          styles.menuIconContainer,
          {
            backgroundColor: isDark
              ? JasminColors.night.deep
              : JasminColors.brand.pink50,
          },
        ]}
      >
        <Feather name={icon} size={20} color={JasminColors.brand.pink500} />
      </View>
      <ThemedText type="body" style={styles.menuLabel}>
        {label}
      </ThemedText>
      {showBadge ? (
        <View style={[styles.badge, { backgroundColor: badgeColor }]} />
      ) : null}
      <Feather name="chevron-right" size={20} color={textMuted} />
    </Pressable>
  );
}

export default function ProfileScreen() {
  const navigation = useNavigation<any>();
  const { theme, isDark } = useTheme();
  const { user, logout, updateAvatar } = useAuth();

  const handleAvatarChange = async (uri: string) => {
    await updateAvatar(uri);
    Alert.alert("Photo Updated", "Your profile photo has been updated.");
  };

  const handleLogout = async () => {
    if (Platform.OS === "web") {
      const confirmed = window.confirm("Are you sure you want to sign out?");
      if (confirmed) {
        await logout();
      }
    } else {
      Alert.alert("Sign Out", "Are you sure you want to sign out?", [
        { text: "Cancel", style: "cancel" },
        {
          text: "Sign Out",
          style: "destructive",
          onPress: async () => {
            await logout();
          },
        },
      ]);
    }
  };

  return (
    <ScreenScrollView>
      <LogoHeader showBackButton={false} />

      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <GlassCard style={styles.profileCard}>
          <View style={styles.avatarContainer}>
            <AvatarPicker
              currentAvatar={user?.avatar}
