import React, { useState } from "react";
import {
  View,
  StyleSheet,
  TextInput,
  Pressable,
  Alert,
  KeyboardAvoidingView,
  Platform,
  ActivityIndicator,
  Image,
} from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { Feather } from "@expo/vector-icons";
import Animated, { FadeInDown, FadeIn } from "react-native-reanimated";
import * as WebBrowser from "expo-web-browser";
import Constants from "expo-constants";

import { ThemedText } from "@/components/ThemedText";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";
import { AuthStackParamList } from "@/navigation/AuthNavigator";

WebBrowser.maybeCompleteAuthSession();

type LoginScreenProps = {
  navigation: NativeStackNavigationProp<AuthStackParamList, "Login">;
};

const GOOGLE_CLIENT_ID = Constants.expoConfig?.extra?.googleClientId || process.env.EXPO_PUBLIC_GOOGLE_CLIENT_ID || "";

export default function LoginScreen({ navigation }: LoginScreenProps) {
  const insets = useSafeAreaInsets();
  const { theme, isDark } = useTheme();
  const { login } = useAuth();

  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
  const [showEmailForm, setShowEmailForm] = useState(false);

  const handleGoogleSignIn = async () => {
    setIsGoogleLoading(true);

    try {
      if (GOOGLE_CLIENT_ID) {
        Alert.alert(
          "Google Sign-In",
          "Google Sign-In is configured but requires a development build. For Expo Go testing, please use email sign-in.",
          [{ text: "Use Email", onPress: () => setShowEmailForm(true) }]
        );
      } else {
        Alert.alert(
          "Google Sign-In",
          "Google Sign-In is ready for production. To enable:\n\n1. Create a Google Cloud project\n2. Set up OAuth 2.0 credentials\n3. Add EXPO_PUBLIC_GOOGLE_CLIENT_ID to your environment\n\nFor beta testing, use email sign-in.",
          [{ text: "Use Email", onPress: () => setShowEmailForm(true) }]
        );
      }
    } catch (error) {
      Alert.alert("Error", "Could not initiate Google sign-in.");
    } finally {
      setIsGoogleLoading(false);
    }
  };

  const handleAppleSignIn = async () => {
    Alert.alert(
      "Apple Sign-In",
      "Apple Sign-In is ready for production. To enable:\n\n1. Configure Apple Developer account\n2. Create Sign in with Apple capability\n3. Build a development build\n\nFor beta testing, use email sign-in.",
      [{ text: "Use Email", onPress: () => setShowEmailForm(true) }]
    );
  };

  const handleEmailLogin = async () => {
    if (!email.trim() || !name.trim()) {
      Alert.alert("Missing Information", "Please enter both your name and email.");
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      Alert.alert("Invalid Email", "Please enter a valid email address.");
      return;
    }

    setIsLoading(true);
    try {
      await new Promise((resolve) => setTimeout(resolve, 600));
      await login(email, name);
    } catch (error) {
      Alert.alert("Error", "Something went wrong. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <KeyboardAvoidingView
      style={styles.container}
      behavior={Platform.OS === "ios" ? "padding" : undefined}
    >
      <Pressable style={styles.backdrop} onPress={() => navigation.goBack()} />

      <Animated.View
        entering={FadeInDown.duration(400).springify()}
        style={[
          styles.card,
          {
            backgroundColor: isDark ? JasminColors.night.base : "#FFFFFF",
            paddingBottom: insets.bottom + Spacing.xl,
          },
        ]}
      >
        <View style={styles.handle} />

        <Pressable style={styles.closeButton} onPress={() => navigation.goBack()}>
          <Feather name="x" size={24} color={theme.textMuted} />
        </Pressable>

        <View style={styles.header}>
          <View style={styles.logoContainer}>
            <Image
              source={require("../assets/images/icon.png")}
              style={styles.logo}
              resizeMode="contain"
            />
          </View>
          <ThemedText type="h3" style={styles.title}>
            Welcome to Jasmin
          </ThemedText>
          <ThemedText type="body" style={styles.subtitle}>
            {showEmailForm
              ? "Enter your details to continue"
              : "Sign in to track your wellness journey"}
          </ThemedText>
        </View>

        {!showEmailForm ? (
          <Animated.View entering={FadeIn.duration(300)} style={styles.authOptions}>
            <Pressable
              style={[
                styles.socialButton,
                {
                  backgroundColor: isDark ? JasminColors.night.surface : "#FFFFFF",
                  borderColor: isDark ? JasminColors.night.deep : JasminColors.gray[200],
                },
              ]}
              onPress={handleGoogleSignIn}
              disabled={isGoogleLoading}
            >
              {isGoogleLoading ? (
                <ActivityIndicator size="small" color={JasminColors.brand.pink500} />
              ) : (
                <>
                  <View style={styles.googleIconContainer}>
                    <Feather name="chrome" size={18} color="#4285F4" />
                  </View>
                  <ThemedText type="body" style={styles.socialButtonText}>
                    Continue with Google
                  </ThemedText>
                </>
              )}
            </Pressable>

            {Platform.OS === "ios" && (
              <Pressable
                style={[
                  styles.socialButton,
                  {
                    backgroundColor: isDark ? "#FFFFFF" : "#000000",
                    borderColor: isDark ? "#FFFFFF" : "#000000",
                  },
                ]}
                onPress={handleAppleSignIn}
              >
                <Feather
                  name="smartphone"
                  size={18}
                  color={isDark ? "#000000" : "#FFFFFF"}
                />
                <ThemedText
                  type="body"
                  style={[
                    styles.socialButtonText,
                    { color: isDark ? "#000000" : "#FFFFFF" },
                  ]}
                >
                  Continue with Apple
                </ThemedText>
              </Pressable>
            )}

            <View style={styles.divider}>
              <View style={[styles.dividerLine, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[200] }]} />
              <ThemedText type="small" style={styles.dividerText}>
                or
              </ThemedText>
              <View style={[styles.dividerLine, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[200] }]} />
            </View>

            <Pressable
              style={[
                styles.emailButton,
                {
                  backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[100],
                },
              ]}
              onPress={() => setShowEmailForm(true)}
            >
              <Feather name="mail" size={18} color={theme.text} />
              <ThemedText type="body" style={styles.emailButtonText}>
                Continue with Email
              </ThemedText>
            </Pressable>
          </Animated.View>
        ) : (
          <Animated.View entering={FadeIn.duration(300)} style={styles.form}>
            <Pressable
              style={styles.backToOptions}
              onPress={() => setShowEmailForm(false)}
            >
              <Feather name="arrow-left" size={16} color={JasminColors.brand.pink500} />
              <ThemedText type="small" style={{ color: JasminColors.brand.pink500 }}>
                Other sign-in options
              </ThemedText>
            </Pressable>

            <View style={styles.inputGroup}>
              <ThemedText type="small" style={styles.label}>
                Your Name
              </ThemedText>
              <TextInput
                style={[
                  styles.input,
                  {
                    backgroundColor: isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[50],
                    color: theme.text,
                  },
                ]}
                value={name}
                onChangeText={setName}
                placeholder="Enter your name"
                placeholderTextColor={theme.placeholder}
                autoCapitalize="words"
                returnKeyType="next"
              />
            </View>

            <View style={styles.inputGroup}>
              <ThemedText type="small" style={styles.label}>
                Email Address
              </ThemedText>
              <TextInput
                style={[
                  styles.input,
                  {
                    backgroundColor: isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[50],
                    color: theme.text,
                  },
                ]}
                value={email}
                onChangeText={setEmail}
                placeholder="your.email@example.com"
                placeholderTextColor={theme.placeholder}
                keyboardType="email-address"
                autoCapitalize="none"
                autoCorrect={false}
                returnKeyType="done"
                onSubmitEditing={handleEmailLogin}
              />
            </View>

            <Button
              onPress={handleEmailLogin}
              disabled={isLoading}
              style={styles.button}
            >
              {isLoading ? "Signing in..." : "Continue"}
            </Button>

            <ThemedText type="small" style={styles.hint}>
              Tip: Use admin@jasmin.app to access admin features
            </ThemedText>
          </Animated.View>
        )}

        <ThemedText type="small" style={styles.termsText}>
          By continuing, you agree to our{" "}
          <ThemedText type="small" style={styles.termsLink}>
            Terms of Service
          </ThemedText>{" "}
          and{" "}
          <ThemedText type="small" style={styles.termsLink}>
            Privacy Policy
          </ThemedText>
        </ThemedText>
      </Animated.View>
    </KeyboardAvoidingView>
  );
}

