import React, { useState, useEffect } from "react";
import { View, StyleSheet, Switch, Alert, Platform, Pressable, Linking, TextInput } from "react-native";
import { Feather } from "@expo/vector-icons";
import * as LocalAuthentication from "expo-local-authentication";
import Animated, { FadeInDown } from "react-native-reanimated";
import DateTimePicker from "@react-native-community/datetimepicker";

import { ThemedText } from "@/components/ThemedText";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { LanguagePicker, LanguageSettingRow } from "@/components/LanguagePicker";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import { useLanguage } from "@/context/LanguageContext";
import { storage } from "@/services/storage";
import { authApi } from "@/services/api";
import { useDiscreetMode } from "@/context/DiscreetModeContext";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

export default function SettingsScreen() {
  const { theme, isDark } = useTheme();
  const { cycleConfig, updateCycleConfig, logout } = useAuth();
  const { t } = useLanguage();
  const { isDiscreetMode, toggleDiscreetMode } = useDiscreetMode();

  const [lastPeriodDate, setLastPeriodDate] = useState(
    cycleConfig ? new Date(cycleConfig.lastPeriodDate) : new Date()
  );
  const [cycleLength, setCycleLength] = useState(cycleConfig?.cycleLength || 28);
  const [periodLength, setPeriodLength] = useState(cycleConfig?.periodLength || 5);
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [showLanguagePicker, setShowLanguagePicker] = useState(false);
  const [notificationsEnabled, setNotificationsEnabled] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [biometricEnabled, setBiometricEnabled] = useState(false);
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [biometricType, setBiometricType] = useState<string>("Biometric");

  useEffect(() => {
    checkBiometricSupport();
    loadBiometricSetting();
  }, []);

  const checkBiometricSupport = async () => {
    if (Platform.OS === "web") {
      setBiometricAvailable(false);
      return;
    }

    const hasHardware = await LocalAuthentication.hasHardwareAsync();
    const isEnrolled = await LocalAuthentication.isEnrolledAsync();
    setBiometricAvailable(hasHardware && isEnrolled);

    if (hasHardware) {
      const types = await LocalAuthentication.supportedAuthenticationTypesAsync();
      if (types.includes(LocalAuthentication.AuthenticationType.FACIAL_RECOGNITION)) {
        setBiometricType("Face ID");
      } else if (types.includes(LocalAuthentication.AuthenticationType.FINGERPRINT)) {
        setBiometricType("Touch ID");
      }
    }
  };

  const loadBiometricSetting = async () => {
    const enabled = await storage.isBiometricEnabled();
    setBiometricEnabled(enabled);
  };

  const handleBiometricToggle = async (value: boolean) => {
    if (value) {
      const result = await LocalAuthentication.authenticateAsync({
        promptMessage: `Enable ${biometricType} for Jasmin`,
        disableDeviceFallback: false,
        cancelLabel: "Cancel",
      });

      if (result.success) {
        await storage.setBiometricEnabled(true);
        setBiometricEnabled(true);
        Alert.alert("Enabled", `${biometricType} has been enabled for Jasmin.`);
      } else {
        Alert.alert("Failed", "Authentication was not successful.");
      }
    } else {
      await storage.setBiometricEnabled(false);
      setBiometricEnabled(false);
    }
  };

  const handleSaveCycleSettings = async () => {
    setIsSaving(true);
    try {
      await updateCycleConfig({
        lastPeriodDate: lastPeriodDate.toISOString(),
        cycleLength,
        periodLength,
      });
      Alert.alert("Saved", "Your cycle settings have been updated.");
    } catch (error) {
      Alert.alert("Error", "Failed to save settings.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleClearData = () => {
    Alert.alert(
      "Clear All Data",
      "This will delete all your journal entries and reset your settings. This action cannot be undone.",
      [
        { text: "Cancel", style: "cancel" },
        {
          text: "Clear Data",
          style: "destructive",
          onPress: async () => {
            await storage.clearAll();
            await logout();
          },
        },
      ]
    );
  };

  const handleDeleteAccount = () => {
    if (Platform.OS === "web") {
      const confirmed = window.confirm(
        "Are you sure you want to permanently delete your account? This action cannot be undone. All your data including cycle history, journal entries, orders, and personal information will be permanently removed."
      );
      if (confirmed) {
        const reconfirm = window.confirm(
          "This is your final confirmation. Type 'DELETE' to proceed."
        );
        if (reconfirm) {
          performAccountDeletion();
        }
      }
    } else {
      Alert.alert(
        "Delete Account",
        "Are you sure you want to permanently delete your account?\n\nThis action cannot be undone. All your data including:\n\n• Cycle tracking history\n• Journal entries\n• Orders and purchases\n• Personal information\n\nwill be permanently removed.",
        [
          { text: "Cancel", style: "cancel" },
          {
            text: "Delete Account",
            style: "destructive",
            onPress: () => {
              Alert.alert(
                "Final Confirmation",
                "This is permanent and cannot be recovered. Are you absolutely sure?",
                [
                  { text: "Cancel", style: "cancel" },
                  {
                    text: "Yes, Delete My Account",
                    style: "destructive",
                    onPress: performAccountDeletion,
                  },
                ]
              );
            },
          },
        ]
      );
    }
  };

  const performAccountDeletion = async () => {
    try {
      await authApi.deleteAccount();
      await storage.clearAll();
      Alert.alert(
        "Account Deleted",
        "Your account has been permanently deleted. Thank you for using Jasmin.",
        [{ text: "OK", onPress: () => logout() }]
      );
    } catch (error) {
      await storage.clearAll();
      await logout();
    }
  };

  const handleOpenPrivacyPolicy = () => {
    Linking.openURL("https://jasmin.app/privacy");
  };

  const handleOpenTerms = () => {
    Linking.openURL("https://jasmin.app/terms");
  };

  const handleDateChange = (event: any, selectedDate?: Date) => {
    setShowDatePicker(Platform.OS === "ios");
    if (selectedDate) {
      setLastPeriodDate(selectedDate);
    }
  };

  return (
    <ScreenScrollView>
      <Animated.View entering={FadeInDown.delay(50).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          {t("settings.language").toUpperCase()}
        </ThemedText>
        <GlassCard style={styles.card}>
          {showLanguagePicker ? (
            <LanguagePicker onClose={() => setShowLanguagePicker(false)} />
          ) : (
            <LanguageSettingRow onPress={() => setShowLanguagePicker(true)} />
          )}
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          {t("profile.cycleSettings").toUpperCase()}
        </ThemedText>
        <GlassCard style={styles.card}>
          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="calendar"
                size={20}
                color={JasminColors.brand.pink500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Last Period Start
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  {lastPeriodDate.toLocaleDateString("en-US", {
                    month: "long",
                    day: "numeric",
                    year: "numeric",
                  })}
                </ThemedText>
              </View>
            </View>
            <Button
              variant="ghost"
              size="small"
              onPress={() => setShowDatePicker(true)}
            >
              Edit
            </Button>
          </View>

          {showDatePicker ? (
            <DateTimePicker
              value={lastPeriodDate}
              mode="date"
              display={Platform.OS === "ios" ? "spinner" : "default"}
              onChange={handleDateChange}
              maximumDate={new Date()}
            />
          ) : null}

          <View style={styles.divider} />

          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="repeat"
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Cycle Length
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  {cycleLength} days
                </ThemedText>
              </View>
            </View>
            <View style={styles.stepperContainer}>
              <Button
                variant="secondary"
                size="small"
                onPress={() => setCycleLength(Math.max(21, cycleLength - 1))}
                style={styles.stepperButton}
              >
                -
              </Button>
              <ThemedText type="body" style={styles.stepperValue}>
                {cycleLength}
              </ThemedText>
              <Button
                variant="secondary"
                size="small"
                onPress={() => setCycleLength(Math.min(35, cycleLength + 1))}
                style={styles.stepperButton}
              >
                +
              </Button>
            </View>
          </View>

          <View style={styles.divider} />

          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="droplet"
                size={20}
                color={JasminColors.brand.pink500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Period Length
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  {periodLength} days
                </ThemedText>
              </View>
            </View>
            <View style={styles.stepperContainer}>
              <Button
                variant="secondary"
                size="small"
                onPress={() => setPeriodLength(Math.max(3, periodLength - 1))}
                style={styles.stepperButton}
              >
                -
              </Button>
              <ThemedText type="body" style={styles.stepperValue}>
                {periodLength}
              </ThemedText>
              <Button
                variant="secondary"
                size="small"
                onPress={() => setPeriodLength(Math.min(7, periodLength + 1))}
                style={styles.stepperButton}
              >
                +
              </Button>
            </View>
          </View>

          <Button
            onPress={handleSaveCycleSettings}
            disabled={isSaving}
            style={styles.saveButton}
          >
            {isSaving ? "Saving..." : "Save Changes"}
          </Button>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          SECURITY
        </ThemedText>
        <GlassCard style={styles.card}>
          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name={biometricType === "Face ID" ? "eye" : "lock"}
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  {biometricType}
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  {biometricAvailable
                    ? "Secure access to sensitive data"
                    : Platform.OS === "web"
                    ? "Available on mobile devices"
                    : "Not available on this device"}
                </ThemedText>
              </View>
            </View>
            <Switch
              value={biometricEnabled}
              onValueChange={handleBiometricToggle}
              trackColor={{
                false: JasminColors.gray[300],
                true: JasminColors.brand.pink500,
              }}
              thumbColor="#FFFFFF"
              disabled={!biometricAvailable}
            />
          </View>

          <View style={styles.divider} />

          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="eye-off"
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Discreet Mode
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  Hide sensitive cycle information
                </ThemedText>
              </View>
            </View>
            <Switch
              value={isDiscreetMode}
              onValueChange={toggleDiscreetMode}
              trackColor={{
                false: JasminColors.gray[300],
                true: JasminColors.brand.purple500,
              }}
              thumbColor="#FFFFFF"
            />
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(300).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          NOTIFICATIONS
        </ThemedText>
        <GlassCard style={styles.card}>
          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="bell"
                size={20}
                color={JasminColors.brand.teal600}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Push Notifications
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  Get reminders and insights
                </ThemedText>
              </View>
            </View>
            <Switch
              value={notificationsEnabled}
              onValueChange={setNotificationsEnabled}
              trackColor={{
                false: JasminColors.gray[300],
                true: JasminColors.brand.pink500,
              }}
              thumbColor="#FFFFFF"
            />
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(400).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          DATA & PRIVACY
        </ThemedText>
        <GlassCard style={styles.card}>
          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="download"
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Export Data
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  Download your cycle history
                </ThemedText>
              </View>
            </View>
            <Button
              variant="ghost"
              size="small"
              onPress={() => Alert.alert("Export", "Go to Profile > Export Data for full export options.")}
            >
              Export
            </Button>
          </View>

          <View style={styles.divider} />

          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="trash-2"
                size={20}
                color={JasminColors.gray[500]}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Clear All Data
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  Delete all local data
                </ThemedText>
              </View>
            </View>
            <Button
              variant="ghost"
              size="small"
              onPress={handleClearData}
            >
              Clear
            </Button>
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(450).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          LEGAL
        </ThemedText>
        <GlassCard style={styles.card}>
          <Pressable style={styles.linkRow} onPress={handleOpenPrivacyPolicy}>
            <View style={styles.settingInfo}>
              <Feather
                name="shield"
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Privacy Policy
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  How we protect your data
                </ThemedText>
              </View>
            </View>
            <Feather name="external-link" size={18} color={JasminColors.gray[400]} />
          </Pressable>

          <View style={styles.divider} />

          <Pressable style={styles.linkRow} onPress={handleOpenTerms}>
            <View style={styles.settingInfo}>
              <Feather
                name="file-text"
                size={20}
                color={JasminColors.brand.purple500}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={styles.settingLabel}>
                  Terms of Service
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  User agreement and policies
                </ThemedText>
              </View>
            </View>
            <Feather name="external-link" size={18} color={JasminColors.gray[400]} />
          </Pressable>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(500).duration(500)}>
        <ThemedText type="sectionHeader" style={[styles.sectionLabel, { color: JasminColors.functional.danger }]}>
          DANGER ZONE
        </ThemedText>
        <GlassCard style={[styles.card, styles.dangerCard]}>
          <View style={styles.settingRow}>
            <View style={styles.settingInfo}>
              <Feather
                name="user-x"
                size={20}
                color={JasminColors.functional.danger}
              />
              <View style={styles.settingText}>
                <ThemedText type="body" style={[styles.settingLabel, { color: JasminColors.functional.danger }]}>
                  Delete Account
                </ThemedText>
                <ThemedText type="small" style={styles.settingValue}>
                  Permanently delete your account and all data
                </ThemedText>
              </View>
            </View>
            <Button
              variant="ghost"
              size="small"
              onPress={handleDeleteAccount}
            >
              <ThemedText
                type="body"
                style={{ color: JasminColors.functional.danger }}
              >
                Delete
              </ThemedText>
            </Button>
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(500).duration(500)}>
        <ThemedText type="small" style={styles.version}>
          Jasmin v1.0.0
        </ThemedText>
      </Animated.View>
    </ScreenScrollView>
  );
}

const styles = StyleSheet.create({
