import React, { useState } from "react";
import { View, StyleSheet, Pressable, Image, Alert, Platform } from "react-native";
import { Feather } from "@expo/vector-icons";
import * as ImagePicker from "expo-image-picker";
import Animated, { FadeIn, useAnimatedStyle, useSharedValue, withSpring } from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

interface AvatarPickerProps {
  currentAvatar?: string | null;
  onAvatarChange: (uri: string) => void;
  size?: number;
}

const AnimatedPressable = Animated.createAnimatedComponent(Pressable);

export function AvatarPicker({
  currentAvatar,
  onAvatarChange,
  size = 100,
}: AvatarPickerProps) {
  const { theme, isDark } = useTheme();
  const [isLoading, setIsLoading] = useState(false);
  const scale = useSharedValue(1);

  const [cameraPermission, requestCameraPermission] = ImagePicker.useCameraPermissions();
  const [mediaPermission, requestMediaPermission] = ImagePicker.useMediaLibraryPermissions();

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  const handlePressIn = () => {
    scale.value = withSpring(0.95, { damping: 15, stiffness: 150 });
  };

  const handlePressOut = () => {
    scale.value = withSpring(1, { damping: 15, stiffness: 150 });
  };

  const showImageOptions = () => {
    Alert.alert(
      "Change Photo",
      "Choose how you'd like to update your photo",
      [
        {
          text: "Take Photo",
          onPress: handleTakePhoto,
        },
        {
          text: "Choose from Library",
          onPress: handleChooseFromLibrary,
        },
        {
          text: "Cancel",
          style: "cancel",
        },
      ]
    );
  };

  const handleTakePhoto = async () => {
    if (Platform.OS === "web") {
      Alert.alert(
        "Camera Not Available",
        "Run in Expo Go to use the camera feature."
      );
      return;
    }

    if (!cameraPermission?.granted) {
      if (cameraPermission?.canAskAgain) {
        const result = await requestCameraPermission();
        if (!result.granted) {
          Alert.alert(
            "Camera Access Required",
            "Please enable camera access in Settings to take photos."
          );
          return;
        }
      } else {
        Alert.alert(
          "Camera Access Required",
          "Please enable camera access in Settings to take photos.",
          [
            { text: "Cancel", style: "cancel" },
            {
              text: "Open Settings",
              onPress: async () => {
                try {
                  const { Linking } = await import("expo-linking");
                  await Linking.openSettings();
                } catch (e) {
                  console.log("Could not open settings");
                }
              },
            },
          ]
        );
        return;
      }
    }

    setIsLoading(true);
    try {
      const result = await ImagePicker.launchCameraAsync({
        mediaTypes: ImagePicker.MediaTypeOptions.Images,
        allowsEditing: true,
        aspect: [1, 1],
        quality: 0.8,
      });

      if (!result.canceled && result.assets[0]) {
        onAvatarChange(result.assets[0].uri);
      }
    } catch (error) {
      Alert.alert("Error", "Failed to take photo. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleChooseFromLibrary = async () => {
    if (!mediaPermission?.granted) {
      if (mediaPermission?.canAskAgain) {
        const result = await requestMediaPermission();
        if (!result.granted) {
          Alert.alert(
            "Photo Library Access Required",
            "Please enable photo library access in Settings."
          );
          return;
        }
      } else {
        Alert.alert(
          "Photo Library Access Required",
          "Please enable photo library access in Settings.",
          [
            { text: "Cancel", style: "cancel" },
            {
              text: "Open Settings",
              onPress: async () => {
                if (Platform.OS !== "web") {
                  try {
                    const { Linking } = await import("expo-linking");
                    await Linking.openSettings();
                  } catch (e) {
                    console.log("Could not open settings");
                  }
                }
              },
            },
          ]
        );
        return;
      }
    }

    setIsLoading(true);
    try {
      const result = await ImagePicker.launchImageLibraryAsync({
        mediaTypes: ImagePicker.MediaTypeOptions.Images,
        allowsEditing: true,
        aspect: [1, 1],
        quality: 0.8,
      });

      if (!result.canceled && result.assets[0]) {
        onAvatarChange(result.assets[0].uri);
      }
    } catch (error) {
      Alert.alert("Error", "Failed to select photo. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AnimatedPressable
      onPress={showImageOptions}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      style={animatedStyle}
      disabled={isLoading}
    >
      <View
        style={[
          styles.container,
          {
            width: size,
            height: size,
            borderRadius: size / 2,
            backgroundColor: isDark
              ? JasminColors.night.deep
              : JasminColors.brand.pink100,
          },
        ]}
      >
        {currentAvatar ? (
          <Image
            source={{ uri: currentAvatar }}
            style={[
              styles.avatar,
              {
                width: size,
                height: size,
                borderRadius: size / 2,
              },
            ]}
          />
        ) : (
          <Feather
            name="user"
            size={size * 0.4}
            color={JasminColors.brand.pink500}
          />
        )}

        <View
          style={[
            styles.editBadge,
            {
              backgroundColor: JasminColors.brand.pink500,
              bottom: 0,
              right: 0,
            },
          ]}
        >
          <Feather name="camera" size={14} color="#FFFFFF" />
        </View>
      </View>
    </AnimatedPressable>
  );
}

const styles = StyleSheet.create({
  container: {
    alignItems: "center",
    justifyContent: "center",
    overflow: "hidden",
  },
  avatar: {
    resizeMode: "cover",
  },
  editBadge: {
    position: "absolute",
    width: 28,
    height: 28,
    borderRadius: 14,
    alignItems: "center",
    justifyContent: "center",
    borderWidth: 2,
    borderColor: "#FFFFFF",
  },
});

screens/NotificationSettingsScreen.tsx.content:
import React, { useState, useEffect } from "react";
import { View, StyleSheet, Switch, Alert, Platform } from "react-native";
import { Feather } from "@expo/vector-icons";
import * as Notifications from "expo-notifications";
import Animated, { FadeInDown } from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { GlassCard } from "@/components/GlassCard";
import { useTheme } from "@/hooks/useTheme";
import { storage } from "@/services/storage";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

interface NotificationSettings {
  cycleReminders: boolean;
  periodPrediction: boolean;
  ovulationAlert: boolean;
  journalReminder: boolean;
  productDeals: boolean;
}

const DEFAULT_SETTINGS: NotificationSettings = {
  cycleReminders: true,
  periodPrediction: true,
  ovulationAlert: true,
  journalReminder: false,
  productDeals: false,
};

Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: false,
  }),
});

export default function NotificationSettingsScreen() {
  const { theme, isDark } = useTheme();
  const [hasPermission, setHasPermission] = useState(false);
  const [settings, setSettings] = useState<NotificationSettings>(DEFAULT_SETTINGS);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkPermissions();
    loadSettings();
  }, []);

  const checkPermissions = async () => {
    if (Platform.OS === "web") {
      setHasPermission(false);
      return;
    }

    const { status } = await Notifications.getPermissionsAsync();
    setHasPermission(status === "granted");
  };

  const loadSettings = async () => {
    try {
      const savedSettings = await storage.getNotificationSettings();
      if (savedSettings) {
        setSettings(savedSettings);
      }
    } catch (error) {
      console.error("Failed to load notification settings:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const requestPermission = async () => {
    if (Platform.OS === "web") {
      Alert.alert(
        "Not Available",
        "Push notifications are only available on mobile devices. Try Jasmin in Expo Go for the full experience."
      );
      return;
    }

    const { status } = await Notifications.requestPermissionsAsync();
    setHasPermission(status === "granted");

    if (status !== "granted") {
      Alert.alert(
        "Permission Required",
        "Enable notifications in your device settings to receive cycle reminders and alerts."
      );
    }
  };

  const updateSetting = async (key: keyof NotificationSettings, value: boolean) => {
    if (!hasPermission && value) {
      await requestPermission();
      return;
    }

    const newSettings = { ...settings, [key]: value };
    setSettings(newSettings);
    await storage.setNotificationSettings(newSettings);

    if (value) {
      scheduleNotification(key);
    } else {
      cancelNotification(key);
    }
  };

  const scheduleNotification = async (type: keyof NotificationSettings) => {
    try {
      switch (type) {
        case "journalReminder":
          await Notifications.scheduleNotificationAsync({
            content: {
              title: "Time to Journal",
              body: "Take a moment to log how you're feeling today.",
            },
            trigger: {
              hour: 20,
              minute: 0,
              repeats: true,
            },
          });
          break;
      }
    } catch (error) {
      console.error("Failed to schedule notification:", error);
    }
  };

  const cancelNotification = async (type: keyof NotificationSettings) => {
    await Notifications.cancelAllScheduledNotificationsAsync();
  };

  const NotificationItem = ({
    icon,
    title,
    description,
    settingKey,
  }: {
    icon: React.ComponentProps<typeof Feather>["name"];
    title: string;
    description: string;
    settingKey: keyof NotificationSettings;
  }) => (
    <View style={styles.settingItem}>
      <View
        style={[
          styles.settingIcon,
          {
            backgroundColor: isDark
              ? JasminColors.night.deep
              : JasminColors.brand.pink50,
          },
        ]}
      >
        <Feather name={icon} size={20} color={JasminColors.brand.pink500} />
      </View>
      <View style={styles.settingInfo}>
        <ThemedText type="body" style={styles.settingTitle}>
          {title}
        </ThemedText>
        <ThemedText type="small" style={styles.settingDescription}>
          {description}
        </ThemedText>
      </View>
      <Switch
        value={settings[settingKey]}
        onValueChange={(value) => updateSetting(settingKey, value)}
        trackColor={{
          false: JasminColors.gray[300],
          true: JasminColors.brand.pink500,
        }}
        thumbColor="#FFFFFF"
        disabled={isLoading}
      />
    </View>
  );

  return (
    <ScreenScrollView>
      {!hasPermission && Platform.OS !== "web" ? (
        <Animated.View entering={FadeInDown.delay(100).duration(500)}>
          <GlassCard style={styles.permissionCard}>
            <View style={styles.permissionHeader}>
              <Feather
                name="bell-off"
                size={24}
                color={JasminColors.functional.warning}
              />
              <ThemedText type="h4" style={styles.permissionTitle}>
                Notifications Disabled
              </ThemedText>
            </View>
            <ThemedText type="body" style={styles.permissionDescription}>
              Enable notifications to receive important cycle reminders and wellness alerts.
            </ThemedText>
            <GlassCard
              onPress={requestPermission}
              style={styles.enableButton}
            >
              <ThemedText type="body" style={styles.enableButtonText}>
                Enable Notifications
              </ThemedText>
            </GlassCard>
          </GlassCard>
        </Animated.View>
      ) : null}

