import React, { useState, useMemo } from "react";
import { View, StyleSheet, Alert, Platform } from "react-native";
import { Feather } from "@expo/vector-icons";
import * as Print from "expo-print";
import * as Sharing from "expo-sharing";
import Animated, { FadeInDown } from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import { storage, JournalEntry } from "@/services/storage";
import { calculateCycleInfo, getPhaseName } from "@/services/cycleService";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

export default function ExportDataScreen() {
  const { theme, isDark } = useTheme();
  const { user, cycleConfig } = useAuth();

  const [isExportingPDF, setIsExportingPDF] = useState(false);
  const [isExportingCSV, setIsExportingCSV] = useState(false);

  const cycleInfo = useMemo(() => calculateCycleInfo(cycleConfig), [cycleConfig]);

  const generatePDFContent = async () => {
    const entries = await storage.getJournalEntries();

    const entriesHTML = entries.slice(0, 30).map(entry => `
      <tr>
        <td>${new Date(entry.date).toLocaleDateString()}</td>
        <td>${entry.mood}</td>
        <td>${entry.symptoms.join(", ") || "None"}</td>
        <td>${entry.notes || "-"}</td>
      </tr>
    `).join("");

    return `
      <!DOCTYPE html>
      <html>
        <head>
          <meta charset="utf-8">
          <title>Jasmin Health Report</title>
          <style>
            body {
              font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
              padding: 40px;
              color: #333;
            }
            .header {
              text-align: center;
              margin-bottom: 30px;
              padding-bottom: 20px;
              border-bottom: 2px solid #EC4899;
            }
            .logo {
              font-size: 28px;
              font-weight: bold;
              background: linear-gradient(90deg, #EC4899, #9333EA);
              -webkit-background-clip: text;
              -webkit-text-fill-color: transparent;
            }
            .subtitle {
              color: #666;
              margin-top: 5px;
            }
            .section {
              margin: 25px 0;
            }
            .section-title {
              font-size: 16px;
              font-weight: 600;
              color: #9333EA;
              margin-bottom: 15px;
              text-transform: uppercase;
              letter-spacing: 0.5px;
            }
            .info-grid {
              display: grid;
              grid-template-columns: repeat(3, 1fr);
              gap: 15px;
            }
            .info-card {
              background: #F9FAFB;
              padding: 15px;
              border-radius: 8px;
            }
            .info-label {
              font-size: 12px;
              color: #666;
              text-transform: uppercase;
            }
            .info-value {
              font-size: 18px;
              font-weight: 600;
              color: #333;
              margin-top: 5px;
            }
            table {
              width: 100%;
              border-collapse: collapse;
              margin-top: 15px;
            }
            th, td {
              padding: 12px;
              text-align: left;
              border-bottom: 1px solid #E5E7EB;
            }
            th {
              background: #F9FAFB;
              font-weight: 600;
              color: #374151;
            }
            .footer {
              margin-top: 40px;
              text-align: center;
              font-size: 12px;
              color: #9CA3AF;
            }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="logo">Jasmin</div>
            <div class="subtitle">Wellness Report for ${user?.name || "User"}</div>
            <div class="subtitle">Generated on ${new Date().toLocaleDateString()}</div>
          </div>

          <div class="section">
            <div class="section-title">Cycle Overview</div>
            <div class="info-grid">
              <div class="info-card">
                <div class="info-label">Current Day</div>
                <div class="info-value">${cycleInfo.currentDay}</div>
              </div>
              <div class="info-card">
                <div class="info-label">Cycle Length</div>
                <div class="info-value">${cycleConfig?.cycleLength || 28} days</div>
              </div>
              <div class="info-card">
                <div class="info-label">Current Phase</div>
                <div class="info-value">${getPhaseName(cycleInfo.phase)}</div>
              </div>
            </div>
          </div>

          <div class="section">
            <div class="section-title">Journal Entries (Last 30)</div>
            <table>
              <thead>
                <tr>
                  <th>Date</th>
                  <th>Mood</th>
                  <th>Symptoms</th>
                  <th>Notes</th>
                </tr>
              </thead>
              <tbody>
                ${entriesHTML || "<tr><td colspan='4'>No journal entries yet</td></tr>"}
              </tbody>
            </table>
          </div>

          <div class="footer">
            <p>This report was generated by Jasmin - Your Wellness Companion</p>
            <p>All data is stored securely and privately on your device.</p>
          </div>
        </body>
      </html>
    `;
  };

  const handleExportPDF = async () => {
    if (Platform.OS === "web") {
      Alert.alert(
        "PDF Export Not Available",
        "Run in Expo Go to export PDF reports."
      );
      return;
    }

    setIsExportingPDF(true);
    try {
      const html = await generatePDFContent();
      const { uri } = await Print.printToFileAsync({ html });

      if (await Sharing.isAvailableAsync()) {
        await Sharing.shareAsync(uri, {
          mimeType: "application/pdf",
          dialogTitle: "Export Jasmin Report",
          UTI: "com.adobe.pdf",
        });
      } else {
        Alert.alert("Success", "PDF saved to: " + uri);
      }
    } catch (error) {
      console.error("PDF export error:", error);
      Alert.alert("Error", "Failed to export PDF. Please try again.");
    } finally {
      setIsExportingPDF(false);
    }
  };

  const handleExportCSV = async () => {
    setIsExportingCSV(true);
    try {
      const entries = await storage.getJournalEntries();

      const headers = ["Date", "Mood", "Symptoms", "Notes"];
      const rows = entries.map(entry => [
        new Date(entry.date).toLocaleDateString(),
        entry.mood,
        entry.symptoms.join("; "),
        `"${(entry.notes || "").replace(/"/g, '""')}"`,
      ]);

      const csvContent = [
        headers.join(","),
        ...rows.map(row => row.join(","))
      ].join("\n");

      const blob = new Blob([csvContent], { type: "text/csv" });

      if (Platform.OS === "web") {
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = `jasmin-journal-${new Date().toISOString().split("T")[0]}.csv`;
        link.click();
        URL.revokeObjectURL(url);
        Alert.alert("Success", "CSV file downloaded.");
      } else {
        Alert.alert("CSV Export", `${entries.length} journal entries ready for export. Use the PDF export for sharing on mobile.`);
      }
    } catch (error) {
      console.error("CSV export error:", error);
      Alert.alert("Error", "Failed to export CSV. Please try again.");
    } finally {
      setIsExportingCSV(false);
    }
  };

  return (
    <ScreenScrollView>
      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <GlassCard style={styles.infoCard}>
          <View style={styles.iconContainer}>
            <Feather
              name="download"
              size={32}
              color={JasminColors.brand.purple500}
            />
          </View>
          <ThemedText type="h4" style={styles.title}>
            Export Your Data
          </ThemedText>
          <ThemedText type="body" style={styles.description}>
            Download your cycle history and journal entries. Your data belongs to you.
          </ThemedText>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          EXPORT FORMATS
        </ThemedText>

        <GlassCard
          style={styles.exportCard}
          onPress={handleExportPDF}
          disabled={isExportingPDF}
        >
          <View style={styles.exportContent}>
            <View
              style={[
                styles.exportIcon,
                { backgroundColor: JasminColors.brand.pink50 },
              ]}
            >
              <Feather name="file-text" size={24} color={JasminColors.brand.pink500} />
            </View>
            <View style={styles.exportInfo}>
              <ThemedText type="body" style={styles.exportTitle}>
                PDF Report
              </ThemedText>
              <ThemedText type="small" style={styles.exportDescription}>
                Beautifully formatted report with cycle overview and journal entries
              </ThemedText>
            </View>
            <Feather
              name={isExportingPDF ? "loader" : "download"}
              size={20}
              color={theme.textMuted}
            />
          </View>
        </GlassCard>

        <GlassCard
          style={styles.exportCard}
          onPress={handleExportCSV}
          disabled={isExportingCSV}
        >
          <View style={styles.exportContent}>
            <View
              style={[
                styles.exportIcon,
                { backgroundColor: JasminColors.brand.teal50 },
              ]}
            >
              <Feather name="table" size={24} color={JasminColors.brand.teal600} />
            </View>
            <View style={styles.exportInfo}>
              <ThemedText type="body" style={styles.exportTitle}>
                CSV Spreadsheet
              </ThemedText>
              <ThemedText type="small" style={styles.exportDescription}>
                Raw data format compatible with Excel and Google Sheets
              </ThemedText>
            </View>
            <Feather
              name={isExportingCSV ? "loader" : "download"}
              size={20}
              color={theme.textMuted}
            />
          </View>
        </GlassCard>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(300).duration(500)}>
        <GlassCard style={styles.privacyCard}>
          <Feather name="shield" size={20} color={JasminColors.brand.teal600} />
          <ThemedText type="small" style={styles.privacyText}>
            Your health data is stored locally on your device and is never uploaded to external servers. Exports are processed entirely on your device.
          </ThemedText>
        </GlassCard>
      </Animated.View>
    </ScreenScrollView>
  );
}

const styles = StyleSheet.create({
  infoCard: {
    alignItems: "center",
    marginBottom: Spacing.xl,
  },
  iconContainer: {
    width: 64,
    height: 64,
    borderRadius: BorderRadius.lg,
    backgroundColor: "rgba(147, 51, 234, 0.1)",
    alignItems: "center",
    justifyContent: "center",
    marginBottom: Spacing.lg,
  },
  title: {
    marginBottom: Spacing.sm,
  },
  description: {
    textAlign: "center",
    opacity: 0.7,
  },
  sectionLabel: {
    marginBottom: Spacing.md,
  },
  exportCard: {
    marginBottom: Spacing.md,
  },
  exportContent: {
    flexDirection: "row",
    alignItems: "center",
  },
  exportIcon: {
    width: 48,
    height: 48,
    borderRadius: BorderRadius.sm,
    alignItems: "center",
    justifyContent: "center",
    marginRight: Spacing.md,
  },
  exportInfo: {
    flex: 1,
  },
  exportTitle: {
    fontWeight: "600",
    marginBottom: 2,
  },
  exportDescription: {
    opacity: 0.6,
  },
  privacyCard: {
    flexDirection: "row",
    alignItems: "flex-start",
    gap: Spacing.md,
    marginTop: Spacing.lg,
    marginBottom: Spacing.xl,
  },
  privacyText: {
    flex: 1,
    opacity: 0.7,
  },
});

components/GradientLogotype.tsx.content:
import React from "react";
import { View, StyleSheet, Text, Platform } from "react-native";
import Svg, { Defs, LinearGradient, Stop, Text as SvgText } from "react-native-svg";
import MaskedView from "@react-native-masked-view/masked-view";
import { LinearGradient as ExpoLinearGradient } from "expo-linear-gradient";

import { JasminColors, Typography } from "@/constants/theme";

interface GradientLogotypeProps {
  size?: "small" | "medium" | "large";
}

const SIZES = {
  small: 18,
  medium: 24,
  large: 32,
};

export function GradientLogotype({ size = "medium" }: GradientLogotypeProps) {
  const fontSize = SIZES[size];
  const letterSpacing = -0.025 * fontSize;

  if (Platform.OS === "web") {
    return (
      <Text
        style={[
          styles.text,
          {
            fontSize,
            letterSpacing,
            backgroundImage: `linear-gradient(to right, ${JasminColors.brand.pink500}, ${JasminColors.brand.purple600})`,
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            backgroundClip: "text",
          } as any,
        ]}
      >
        Jasmin
      </Text>
    );
  }

  return (
    <MaskedView
      style={{ height: fontSize * 1.2 }}
      maskElement={
        <Text
          style={[
            styles.text,
            {
              fontSize,
              letterSpacing,
              color: "#000",
            },
          ]}
        >
          Jasmin
        </Text>
      }
    >
      <ExpoLinearGradient
        colors={[JasminColors.brand.pink500, JasminColors.brand.purple600]}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 0 }}
        style={{ flex: 1, height: fontSize * 1.2 }}
      />
    </MaskedView>
  );
}

const styles = StyleSheet.create({
  text: {
    fontWeight: "700",
  },
});

components/CheckoutModal.tsx.content:
import React, { useState, useCallback } from "react";
import {
  View,
  StyleSheet,
  Modal,
  Pressable,
  TextInput,
  ScrollView,
  Alert,
  KeyboardAvoidingView,
  Platform,
} from "react-native";
import { Feather } from "@expo/vector-icons";
import Animated, {
  FadeIn,
  FadeInDown,
  SlideInRight,
  SlideOutLeft,
} from "react-native-reanimated";
import { useSafeAreaInsets } from "react-native-safe-area-context";

import { ThemedText } from "@/components/ThemedText";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import {
  storage,
  Order,
  OrderItem,
  DeliveryAddress,
  PaymentMethod,
  OrderType,
} from "@/services/storage";
import { Product, Merchant } from "@/services/mockData";
import { Spacing, BorderRadius, JasminColors, Shadows } from "@/constants/theme";
import { formatRWF } from "@/utils/currency";

type CheckoutStep = "address" | "payment" | "confirmation";

interface CartItem {
  product: Product;
  quantity: number;
}

interface CheckoutModalProps {
  visible: boolean;
  onClose: () => void;
  items: CartItem[];
  merchant: Merchant;
  orderType: OrderType;
  onOrderComplete: (order: Order) => void;
}

const PAYMENT_METHODS: { id: PaymentMethod; label: string; icon: React.ComponentProps<typeof Feather>["name"]; description: string }[] = [
  { id: "mobile_money", label: "Mobile Money", icon: "smartphone", description: "Pay with MTN, Vodafone, or AirtelTigo" },
  { id: "card", label: "Debit/Credit Card", icon: "credit-card", description: "Visa, Mastercard accepted" },
  { id: "cash_on_delivery", label: "Cash on Delivery", icon: "dollar-sign", description: "Pay when you receive your order" },
];

const DELIVERY_FEE = 5.00;
const USD_TO_RWF = 1200;

const formatPrice = (usdAmount: number): string => {
  return formatRWF(usdAmount * USD_TO_RWF);
};

export function CheckoutModal({
  visible,
  onClose,
  items,
  merchant,
  orderType,
  onOrderComplete,
}: CheckoutModalProps) {
  const { theme, isDark } = useTheme();
  const { user } = useAuth();
  const insets = useSafeAreaInsets();

  const [step, setStep] = useState<CheckoutStep>("address");
  const [address, setAddress] = useState<DeliveryAddress>({
    street: "",
    city: "",
    region: "",
    landmark: "",
    phone: "",
  });
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>("mobile_money");
  const [isProcessing, setIsProcessing] = useState(false);

  const subtotal = items.reduce((sum, item) => sum + item.product.price * item.quantity, 0);
  const deliveryFee = orderType === "delivery" ? DELIVERY_FEE : 0;
  const total = subtotal + deliveryFee;

  const isAddressValid = address.street.trim() && address.city.trim() && address.phone.trim();

  const handleNext = () => {
    if (step === "address") {
      if (orderType === "delivery" && !isAddressValid) {
        Alert.alert("Missing Information", "Please fill in your delivery address and phone number.");
        return;
      }
      setStep("payment");
    } else if (step === "payment") {
      setStep("confirmation");
    }
  };

  const handleBack = () => {
    if (step === "payment") {
      setStep("address");
    } else if (step === "confirmation") {
      setStep("payment");
    }
  };

  const handlePlaceOrder = useCallback(async () => {
    if (!user) return;

    setIsProcessing(true);

    const orderItems: OrderItem[] = items.map((item) => ({
      productId: item.product.id,
      productName: item.product.name,
      quantity: item.quantity,
      unitPrice: item.product.price,
    }));

    const now = new Date().toISOString();
    const order: Order = {
      id: Date.now().toString(),
      userId: user.id,
      merchantId: merchant.id,
      items: orderItems,
      orderType,
      paymentMethod,
      deliveryAddress: orderType === "delivery" ? address : undefined,
      subtotal,
      deliveryFee,
      total,
      status: "pending",
      createdAt: now,
      updatedAt: now,
    };

    const success = await storage.addOrder(order);

    setTimeout(() => {
      setIsProcessing(false);
      if (success) {
        onOrderComplete(order);
      } else {
        Alert.alert("Order Failed", "There was a problem saving your order. Please try again.");
      }
    }, 1500);
  }, [user, items, merchant, orderType, paymentMethod, address, subtotal, deliveryFee, total, onOrderComplete]);

  const renderAddressStep = () => (
    <Animated.View entering={FadeInDown.duration(300)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <View style={[styles.stepIcon, { backgroundColor: JasminColors.brand.teal600 + "20" }]}>
          <Feather name="map-pin" size={20} color={JasminColors.brand.teal600} />
        </View>
        <ThemedText type="h4">
          {orderType === "delivery" ? "Delivery Address" : "Pickup Details"}
        </ThemedText>
      </View>

      {orderType === "delivery" ? (
        <View style={styles.form}>
          <View style={styles.inputGroup}>
            <ThemedText type="small" style={styles.inputLabel}>Street Address *</ThemedText>
            <TextInput
              style={[styles.input, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[50], color: theme.text }]}
              value={address.street}
              onChangeText={(text) => setAddress((prev) => ({ ...prev, street: text }))}
              placeholder="123 Main Street, Apt 4"
              placeholderTextColor={theme.placeholder}
            />
          </View>

          <View style={styles.inputRow}>
            <View style={[styles.inputGroup, { flex: 1 }]}>
              <ThemedText type="small" style={styles.inputLabel}>City *</ThemedText>
              <TextInput
                style={[styles.input, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[50], color: theme.text }]}
                value={address.city}
                onChangeText={(text) => setAddress((prev) => ({ ...prev, city: text }))}
                placeholder="Kigali"
                placeholderTextColor={theme.placeholder}
              />
            </View>
            <View style={[styles.inputGroup, { flex: 1 }]}>
              <ThemedText type="small" style={styles.inputLabel}>Region</ThemedText>
              <TextInput
                style={[styles.input, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[50], color: theme.text }]}
                value={address.region}
                onChangeText={(text) => setAddress((prev) => ({ ...prev, region: text }))}
                placeholder="Kigali City"
                placeholderTextColor={theme.placeholder}
              />
            </View>
          </View>

          <View style={styles.inputGroup}>
            <ThemedText type="small" style={styles.inputLabel}>Landmark (Optional)</ThemedText>
            <TextInput
              style={[styles.input, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[50], color: theme.text }]}
              value={address.landmark}
              onChangeText={(text) => setAddress((prev) => ({ ...prev, landmark: text }))}
              placeholder="Near the post office"
              placeholderTextColor={theme.placeholder}
            />
          </View>

          <View style={styles.inputGroup}>
            <ThemedText type="small" style={styles.inputLabel}>Phone Number *</ThemedText>
            <TextInput
              style={[styles.input, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.gray[50], color: theme.text }]}
              value={address.phone}
              onChangeText={(text) => setAddress((prev) => ({ ...prev, phone: text }))}
              placeholder="+250 7XX XXX XXX"
              placeholderTextColor={theme.placeholder}
              keyboardType="phone-pad"
            />
          </View>
        </View>
      ) : (
        <GlassCard style={styles.pickupCard}>
          <View style={styles.pickupRow}>
            <Feather name="home" size={20} color={JasminColors.brand.teal600} />
            <View style={styles.pickupInfo}>
              <ThemedText type="body" style={{ fontWeight: "600" }}>{merchant.name}</ThemedText>
              <ThemedText type="small" style={{ color: theme.textMuted }}>{merchant.address}</ThemedText>
            </View>
          </View>
          <View style={[styles.pickupNote, { backgroundColor: isDark ? JasminColors.night.deep : JasminColors.brand.teal50 }]}>
            <Feather name="info" size={14} color={JasminColors.brand.teal600} />
            <ThemedText type="small" style={{ color: JasminColors.brand.teal600, flex: 1 }}>
              Your order will be ready for pickup in 30-45 minutes
            </ThemedText>
          </View>
        </GlassCard>
      )}
    </Animated.View>
  );

  const renderPaymentStep = () => (
    <Animated.View entering={SlideInRight.duration(300)} exiting={SlideOutLeft.duration(200)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <View style={[styles.stepIcon, { backgroundColor: JasminColors.brand.pink500 + "20" }]}>
          <Feather name="credit-card" size={20} color={JasminColors.brand.pink500} />
        </View>
        <ThemedText type="h4">Payment Method</ThemedText>
      </View>

      <View style={styles.paymentOptions}>
        {PAYMENT_METHODS.map((method) => (
          <Pressable
            key={method.id}
            onPress={() => setPaymentMethod(method.id)}
            style={({ pressed }) => [
              styles.paymentOption,
              {
                backgroundColor: isDark ? JasminColors.night.surface : "#FFFFFF",
                borderColor: paymentMethod === method.id ? JasminColors.brand.pink500 : isDark ? JasminColors.night.deep : JasminColors.gray[200],
                borderWidth: paymentMethod === method.id ? 2 : 1,
                opacity: pressed ? 0.9 : 1,
              },
            ]}
          >
            <View style={[styles.paymentIcon, { backgroundColor: paymentMethod === method.id ? JasminColors.brand.pink500 + "20" : isDark ? JasminColors.night.deep : JasminColors.gray[100] }]}>
              <Feather name={method.icon} size={20} color={paymentMethod === method.id ? JasminColors.brand.pink500 : theme.textMuted} />
            </View>
            <View style={styles.paymentInfo}>
              <ThemedText type="body" style={{ fontWeight: "600" }}>{method.label}</ThemedText>
              <ThemedText type="small" style={{ color: theme.textMuted }}>{method.description}</ThemedText>
            </View>
            <View style={[styles.radio, { borderColor: paymentMethod === method.id ? JasminColors.brand.pink500 : theme.textMuted }]}>
              {paymentMethod === method.id && <View style={[styles.radioInner, { backgroundColor: JasminColors.brand.pink500 }]} />}
            </View>
          </Pressable>
        ))}
      </View>
    </Animated.View>
  );

  const renderConfirmationStep = () => (
    <Animated.View entering={SlideInRight.duration(300)} style={styles.stepContent}>
      <View style={styles.stepHeader}>
        <View style={[styles.stepIcon, { backgroundColor: JasminColors.brand.purple500 + "20" }]}>
          <Feather name="check-circle" size={20} color={JasminColors.brand.purple500} />
        </View>
        <ThemedText type="h4">Review Order</ThemedText>
      </View>

      <GlassCard style={styles.summaryCard}>
        <ThemedText type="sectionHeader" style={styles.summaryTitle}>ORDER SUMMARY</ThemedText>
        {items.map((item) => (
          <View key={item.product.id} style={styles.summaryItem}>
            <View style={styles.itemInfo}>
              <ThemedText type="body">{item.product.name}</ThemedText>
              <ThemedText type="small" style={{ color: theme.textMuted }}>Qty: {item.quantity}</ThemedText>
            </View>
            <ThemedText type="body" style={{ fontWeight: "600" }}>{formatPrice(item.product.price * item.quantity)}</ThemedText>
          </View>
        ))}

        <View style={styles.divider} />

        <View style={styles.summaryRow}>
          <ThemedText type="small" style={{ color: theme.textMuted }}>Subtotal</ThemedText>
          <ThemedText type="body">{formatPrice(subtotal)}</ThemedText>
        </View>

        {orderType === "delivery" && (
          <View style={styles.summaryRow}>
            <ThemedText type="small" style={{ color: theme.textMuted }}>Delivery Fee</ThemedText>
            <ThemedText type="body">{formatPrice(deliveryFee)}</ThemedText>
          </View>
        )}

        <View style={[styles.summaryRow, styles.totalRow]}>
          <ThemedText type="h4">Total</ThemedText>
          <ThemedText type="h3" style={{ color: JasminColors.brand.pink500 }}>{formatPrice(total)}</ThemedText>
        </View>
      </GlassCard>

      <View style={styles.confirmDetails}>
        <View style={styles.confirmRow}>
          <Feather name={orderType === "delivery" ? "truck" : "shopping-bag"} size={16} color={theme.textMuted} />
          <ThemedText type="small" style={{ color: theme.textMuted, textTransform: "capitalize" }}>{orderType}</ThemedText>
        </View>
        <View style={styles.confirmRow}>
          <Feather name="credit-card" size={16} color={theme.textMuted} />
          <ThemedText type="small" style={{ color: theme.textMuted }}>
            {PAYMENT_METHODS.find((m) => m.id === paymentMethod)?.label}
          </ThemedText>
        </View>
        {orderType === "delivery" && address.street && (
          <View style={styles.confirmRow}>
            <Feather name="map-pin" size={16} color={theme.textMuted} />
            <ThemedText type="small" style={{ color: theme.textMuted, flex: 1 }} numberOfLines={1}>
              {address.street}, {address.city}
            </ThemedText>
          </View>
        )}
      </View>
    </Animated.View>
  );

  const renderStepIndicator = () => (
    <View style={styles.stepIndicator}>
      {(["address", "payment", "confirmation"] as CheckoutStep[]).map((s, index) => (
        <React.Fragment key={s}>
          <View
            style={[
              styles.stepDot,
              {
                backgroundColor:
                  step === s
                    ? JasminColors.brand.pink500
                    : ["address", "payment", "confirmation"].indexOf(step) > index
                    ? JasminColors.brand.teal600
                    : isDark
                    ? JasminColors.night.deep
                    : JasminColors.gray[200],
              },
            ]}
          >
            {["address", "payment", "confirmation"].indexOf(step) > index && (
              <Feather name="check" size={12} color="#FFFFFF" />
            )}
          </View>
          {index < 2 && (
            <View
              style={[
                styles.stepLine,
                {
                  backgroundColor:
                    ["address", "payment", "confirmation"].indexOf(step) > index
                      ? JasminColors.brand.teal600
                      : isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[200],
                },
              ]}
            />
          )}
        </React.Fragment>
      ))}
    </View>
  );

  return (
    <Modal visible={visible} animationType="slide" transparent statusBarTranslucent>
      <KeyboardAvoidingView behavior={Platform.OS === "ios" ? "padding" : undefined} style={styles.container}>
        <View style={styles.overlay}>
          <Animated.View
            entering={FadeIn.duration(300)}
            style={[
              styles.modal,
              {
                backgroundColor: isDark ? JasminColors.night.base : "#FFFFFF",
                paddingBottom: insets.bottom + Spacing.lg,
              },
            ]}
          >
            <View style={styles.header}>
              <Pressable onPress={step === "address" ? onClose : handleBack} style={styles.headerButton}>
                <Feather name={step === "address" ? "x" : "arrow-left"} size={24} color={theme.text} />
              </Pressable>
              <ThemedText type="h4">Checkout</ThemedText>
              <View style={styles.headerButton} />
            </View>

            {renderStepIndicator()}

            <ScrollView style={styles.scrollContent} contentContainerStyle={styles.scrollContainer} showsVerticalScrollIndicator={false} keyboardShouldPersistTaps="handled">
              {step === "address" && renderAddressStep()}
              {step === "payment" && renderPaymentStep()}
              {step === "confirmation" && renderConfirmationStep()}
            </ScrollView>

            <View style={styles.footer}>
              {step === "confirmation" ? (
                <Button
                  onPress={handlePlaceOrder}
                  loading={isProcessing}
                  style={{ backgroundColor: JasminColors.brand.pink500 }}
                >
                  {isProcessing ? "Processing..." : `Place Order - ${formatPrice(total)}`}
                </Button>
              ) : (
                <Button onPress={handleNext}>
                  Continue
                </Button>
              )}
            </View>
          </Animated.View>
        </View>
      </KeyboardAvoidingView>
    </Modal>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  overlay: {
    flex: 1,
    backgroundColor: "rgba(0,0,0,0.5)",
    justifyContent: "flex-end",
  },
  modal: {
    borderTopLeftRadius: BorderRadius.xl,
    borderTopRightRadius: BorderRadius.xl,
    maxHeight: "90%",
  },
