import React, { useState, useMemo } from "react";
import { View, StyleSheet, Pressable, ScrollView, Image, Platform, Linking } from "react-native";
import { Feather } from "@expo/vector-icons";
import { useNavigation } from "@react-navigation/native";
import Animated, { FadeInDown } from "react-native-reanimated";
import { LinearGradient } from "expo-linear-gradient";
import * as ImagePicker from "expo-image-picker";

import { ThemedText } from "@/components/ThemedText";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

const MATERNAL_MEDICINES = [
  {
    id: "1",
    name: "Prenatal Vitamins",
    description: "Complete folic acid + iron supplement",
    price: 24.99,
    stock: 45,
    category: "Supplements",
    image: null,
  },
  {
    id: "2",
    name: "Calcium + D3",
    description: "Bone health support for pregnancy",
    price: 18.50,
    stock: 32,
    category: "Supplements",
    image: null,
  },
  {
    id: "3",
    name: "Anti-Nausea Drops",
    description: "Ginger-based morning sickness relief",
    price: 12.99,
    stock: 8,
    category: "Relief",
    image: null,
  },
  {
    id: "4",
    name: "Iron Supplement",
    description: "For anemia prevention during pregnancy",
    price: 15.00,
    stock: 25,
    category: "Supplements",
    image: null,
  },
  {
    id: "5",
    name: "Stretch Mark Cream",
    description: "Moisturizing formula with vitamin E",
    price: 29.99,
    stock: 4,
    category: "Skincare",
    image: null,
  },
];

const QUICK_CATEGORIES = [
  { id: "supplements", label: "Supplements", icon: "package" as const },
  { id: "relief", label: "Relief", icon: "heart" as const },
  { id: "skincare", label: "Skincare", icon: "droplet" as const },
  { id: "equipment", label: "Equipment", icon: "thermometer" as const },
];

export default function MaternalScreen() {
  const navigation = useNavigation<any>();
  const { theme, isDark } = useTheme();
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [prescriptionImage, setPrescriptionImage] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<"list" | "pharmacies">("list");

  const filteredMedicines = useMemo(() => {
    if (!selectedCategory) return MATERNAL_MEDICINES;
    return MATERNAL_MEDICINES.filter(
      (m) => m.category.toLowerCase() === selectedCategory
    );
  }, [selectedCategory]);

  const handleUploadPrescription = async () => {
    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();

    if (status !== "granted") {
      if (Platform.OS !== "web") {
        try {
          await Linking.openSettings();
        } catch (error) {
          console.log("Could not open settings");
        }
      }
      return;
    }

    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: true,
      quality: 0.8,
    });

    if (!result.canceled && result.assets[0]) {
      setPrescriptionImage(result.assets[0].uri);
    }
  };

  const handleTakePhoto = async () => {
    const { status } = await ImagePicker.requestCameraPermissionsAsync();

    if (status !== "granted") {
      if (Platform.OS !== "web") {
        try {
          await Linking.openSettings();
        } catch (error) {
          console.log("Could not open settings");
        }
      }
      return;
    }

    const result = await ImagePicker.launchCameraAsync({
      allowsEditing: true,
      quality: 0.8,
    });

    if (!result.canceled && result.assets[0]) {
      setPrescriptionImage(result.assets[0].uri);
    }
  };

  const getStockColor = (stock: number) => {
    if (stock <= 5) return JasminColors.functional.danger;
    if (stock <= 10) return JasminColors.functional.warning;
    return JasminColors.brand.emerald500;
  };

  return (
    <ScreenScrollView>
      <Animated.View entering={FadeInDown.delay(100).duration(500)}>
        <LinearGradient
          colors={[JasminColors.maternal.primary, JasminColors.brand.emerald500]}
          start={{ x: 0, y: 0 }}
          end={{ x: 1, y: 1 }}
          style={styles.heroCard}
        >
          <View style={styles.heroContent}>
            <View style={styles.heroIcon}>
              <Feather name="heart" size={24} color="#FFFFFF" />
            </View>
            <ThemedText type="h4" style={styles.heroTitle}>
              Maternal Care
            </ThemedText>
            <ThemedText type="body" style={styles.heroSubtitle}>
              Specialized products for your pregnancy journey
            </ThemedText>
          </View>
        </LinearGradient>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(150).duration(500)}>
        <ThemedText type="sectionHeader" style={styles.sectionLabel}>
          UPLOAD PRESCRIPTION
        </ThemedText>
        <Pressable onPress={handleUploadPrescription}>
          <View
            style={[
              styles.uploadCard,
              {
                backgroundColor: isDark
                  ? JasminColors.night.surface
                  : JasminColors.brand.teal50,
                borderColor: JasminColors.brand.teal600,
              },
            ]}
          >
            {prescriptionImage ? (
              <View style={styles.uploadedContent}>
                <Image
                  source={{ uri: prescriptionImage }}
                  style={styles.prescriptionThumb}
                />
                <View style={styles.uploadedInfo}>
                  <Feather
                    name="check-circle"
                    size={20}
                    color={JasminColors.brand.emerald500}
                  />
                  <ThemedText type="body" style={styles.uploadedText}>
                    Prescription uploaded
                  </ThemedText>
                </View>
                <ThemedText
                  type="small"
                  style={[styles.tapToChange, { color: JasminColors.brand.teal600 }]}
                >
                  Tap to change
                </ThemedText>
              </View>
            ) : (
              <View style={styles.uploadPlaceholder}>
                <View
                  style={[
                    styles.uploadIconContainer,
                    { backgroundColor: JasminColors.brand.teal600 },
                  ]}
                >
                  <Feather name="upload" size={24} color="#FFFFFF" />
                </View>
                <ThemedText type="body" style={styles.uploadTitle}>
                  Upload your prescription
                </ThemedText>
                <ThemedText
                  type="small"
                  style={[styles.uploadHint, { color: JasminColors.brand.teal600 }]}
                >
                  Tap to select from gallery
                </ThemedText>
              </View>
            )}
          </View>
        </Pressable>
      </Animated.View>

      <Animated.View entering={FadeInDown.delay(200).duration(500)}>
        <View style={styles.viewToggle}>
          <ThemedText type="sectionHeader" style={styles.sectionLabel}>
            {viewMode === "list" ? "MEDICINES" : "FIND PHARMACIES"}
          </ThemedText>
          <View style={styles.toggleButtons}>
            <Pressable
              onPress={() => setViewMode("list")}
              style={[
                styles.toggleButton,
                viewMode === "list" && {
                  backgroundColor: JasminColors.brand.teal600,
                },
              ]}
            >
              <Feather
                name="list"
                size={16}
                color={viewMode === "list" ? "#FFFFFF" : theme.textMuted}
              />
            </Pressable>
            <Pressable
              onPress={() => setViewMode("pharmacies")}
              style={[
                styles.toggleButton,
                viewMode === "pharmacies" && {
                  backgroundColor: JasminColors.brand.teal600,
                },
              ]}
            >
              <Feather
                name="map-pin"
                size={16}
                color={viewMode === "pharmacies" ? "#FFFFFF" : theme.textMuted}
              />
            </Pressable>
          </View>
        </View>
      </Animated.View>

      {viewMode === "list" ? (
        <>
          <Animated.View entering={FadeInDown.delay(250).duration(500)}>
            <ScrollView
              horizontal
              showsHorizontalScrollIndicator={false}
              contentContainerStyle={styles.categoryScroll}
            >
              <Pressable
                onPress={() => setSelectedCategory(null)}
                style={[
                  styles.categoryChip,
                  !selectedCategory && {
                    backgroundColor: JasminColors.brand.teal600,
                  },
                  selectedCategory && {
                    backgroundColor: isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[100],
                  },
                ]}
              >
                <ThemedText
                  type="small"
                  style={[
                    styles.categoryLabel,
                    { color: !selectedCategory ? "#FFFFFF" : theme.textSecondary },
                  ]}
                >
                  All
                </ThemedText>
              </Pressable>
              {QUICK_CATEGORIES.map((cat) => (
                <Pressable
                  key={cat.id}
                  onPress={() =>
                    setSelectedCategory(
                      selectedCategory === cat.id ? null : cat.id
                    )
                  }
                  style={[
                    styles.categoryChip,
                    selectedCategory === cat.id && {
                      backgroundColor: JasminColors.brand.teal600,
                    },
                    selectedCategory !== cat.id && {
                      backgroundColor: isDark
                        ? JasminColors.night.deep
                        : JasminColors.gray[100],
                    },
                  ]}
                >
                  <Feather
                    name={cat.icon}
                    size={14}
                    color={
                      selectedCategory === cat.id ? "#FFFFFF" : theme.textSecondary
                    }
                  />
                  <ThemedText
                    type="small"
                    style={[
                      styles.categoryLabel,
                      {
                        color:
                          selectedCategory === cat.id
                            ? "#FFFFFF"
                            : theme.textSecondary,
                      },
                    ]}
                  >
                    {cat.label}
                  </ThemedText>
                </Pressable>
              ))}
            </ScrollView>
          </Animated.View>

          <View style={styles.productList}>
            {filteredMedicines.map((medicine, index) => (
              <Animated.View
                key={medicine.id}
                entering={FadeInDown.delay(300 + index * 50).duration(500)}
              >
                <GlassCard style={styles.productCard}>
                  <View style={styles.productContent}>
                    <View
                      style={[
                        styles.productIcon,
                        { backgroundColor: JasminColors.brand.teal50 },
                      ]}
                    >
                      <Feather
                        name="package"
                        size={20}
                        color={JasminColors.brand.teal600}
                      />
                    </View>
                    <View style={styles.productInfo}>
                      <ThemedText type="body" style={styles.productName}>
                        {medicine.name}
                      </ThemedText>
                      <ThemedText type="small" style={styles.productDesc}>
                        {medicine.description}
                      </ThemedText>
                      <View style={styles.productMeta}>
                        <ThemedText
                          type="body"
                          style={[
                            styles.productPrice,
                            { color: JasminColors.brand.teal600 },
                          ]}
                        >
                          ${medicine.price.toFixed(2)}
                        </ThemedText>
                        <View style={styles.stockBadge}>
                          <View
                            style={[
                              styles.stockDot,
                              { backgroundColor: getStockColor(medicine.stock) },
                            ]}
                          />
                          <ThemedText type="small" style={styles.stockText}>
                            {medicine.stock} in stock
                          </ThemedText>
                        </View>
                      </View>
                    </View>
                    <Pressable
                      style={[
                        styles.addButton,
                        { backgroundColor: JasminColors.brand.teal600 },
                      ]}
                    >
                      <Feather name="plus" size={18} color="#FFFFFF" />
                    </Pressable>
                  </View>
                </GlassCard>
              </Animated.View>
            ))}
          </View>
        </>
      ) : (
        <Animated.View entering={FadeInDown.delay(250).duration(500)}>
          <GlassCard style={styles.mapPlaceholder}>
            <View style={styles.mapContent}>
              <View
                style={[
                  styles.mapIcon,
                  { backgroundColor: JasminColors.brand.teal50 },
                ]}
              >
                <Feather
                  name="map"
                  size={32}
                  color={JasminColors.brand.teal600}
                />
              </View>
              <ThemedText type="h4" style={styles.mapTitle}>
                Pharmacy Finder
              </ThemedText>
              <ThemedText type="body" style={styles.mapSubtitle}>
                Enable location to find nearby pharmacies
              </ThemedText>
              <Button
                onPress={() => {}}
                style={[styles.enableLocationBtn, { backgroundColor: JasminColors.brand.teal600 }]}
              >
                Enable Location
              </Button>
            </View>
          </GlassCard>

          <ThemedText type="sectionHeader" style={styles.sectionLabel}>
            NEARBY PHARMACIES
          </ThemedText>
          {[1, 2, 3].map((i) => (
            <GlassCard key={i} style={styles.pharmacyCard}>
              <View style={styles.pharmacyContent}>
                <View
                  style={[
                    styles.pharmacyIcon,
                    { backgroundColor: JasminColors.brand.teal50 },
                  ]}
                >
                  <Feather
                    name="map-pin"
                    size={20}
                    color={JasminColors.brand.teal600}
                  />
                </View>
                <View style={styles.pharmacyInfo}>
                  <ThemedText type="body" style={styles.pharmacyName}>
                    HealthCare Pharmacy {i}
                  </ThemedText>
                  <ThemedText type="small" style={styles.pharmacyAddress}>
                    123 Main Street, Suite {i}00
                  </ThemedText>
                  <View style={styles.pharmacyMeta}>
                    <View style={styles.distanceBadge}>
                      <Feather
                        name="navigation"
                        size={12}
                        color={JasminColors.brand.teal600}
                      />
                      <ThemedText
                        type="small"
                        style={[
                          styles.distanceText,
                          { color: JasminColors.brand.teal600 },
                        ]}
                      >
                        {0.5 * i} km
                      </ThemedText>
                    </View>
                    <View style={styles.openBadge}>
                      <View
                        style={[
                          styles.openDot,
                          { backgroundColor: JasminColors.brand.emerald500 },
                        ]}
                      />
                      <ThemedText type="small">Open</ThemedText>
                    </View>
                  </View>
                </View>
                <Pressable style={styles.directionsBtn}>
                  <Feather
                    name="navigation"
                    size={18}
                    color={JasminColors.brand.teal600}
                  />
                </Pressable>
              </View>
            </GlassCard>
          ))}
        </Animated.View>
      )}
    </ScreenScrollView>
  );
}

