import React, { useEffect } from "react";
import { View, StyleSheet } from "react-native";
import Svg, { G, Path, Circle, Defs, LinearGradient, RadialGradient, Stop } from "react-native-svg";
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withRepeat,
  withTiming,
  withSequence,
  Easing,
} from "react-native-reanimated";

interface JasminBrandIconProps {
  size?: number;
  animated?: boolean;
  animationType?: "spin" | "pulse" | "none";
  showBackground?: boolean;
}

const AnimatedView = Animated.createAnimatedComponent(View);

export function JasminBrandIcon({
  size = 24,
  animated = false,
  animationType = "none",
  showBackground = false,
}: JasminBrandIconProps) {
  const rotation = useSharedValue(0);
  const scale = useSharedValue(1);
  const opacity = useSharedValue(1);

  useEffect(() => {
    if (animated) {
      if (animationType === "spin") {
        rotation.value = withRepeat(
          withTiming(360, { duration: 3000, easing: Easing.linear }),
          -1,
          false
        );
      } else if (animationType === "pulse") {
        scale.value = withRepeat(
          withSequence(
            withTiming(1.1, { duration: 1000, easing: Easing.inOut(Easing.ease) }),
            withTiming(1, { duration: 1000, easing: Easing.inOut(Easing.ease) })
          ),
          -1,
          false
        );
        opacity.value = withRepeat(
          withSequence(
            withTiming(0.8, { duration: 1000 }),
            withTiming(1, { duration: 1000 })
          ),
          -1,
          false
        );
      }
    }
  }, [animated, animationType]);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [
      { rotate: `${rotation.value}deg` },
      { scale: scale.value },
    ],
    opacity: opacity.value,
  }));

  const centerX = 50;
  const centerY = 50;
  const petalLength = 22;
  const petalWidth = 12;

  const createPetalPath = (angle: number): string => {
    const rad = (angle - 90) * (Math.PI / 180);
    const tipX = centerX + Math.cos(rad) * petalLength;
    const tipY = centerY + Math.sin(rad) * petalLength;

    const perpRad = rad + Math.PI / 2;
    const baseOffset = petalWidth / 2;

    const leftBaseX = centerX + Math.cos(perpRad) * baseOffset;
    const leftBaseY = centerY + Math.sin(perpRad) * baseOffset;
    const rightBaseX = centerX - Math.cos(perpRad) * baseOffset;
    const rightBaseY = centerY - Math.sin(perpRad) * baseOffset;

    const cp1Dist = petalLength * 0.6;
    const cp2Dist = petalLength * 0.8;
    const cpWidth = petalWidth * 0.7;

    const leftCp1X = leftBaseX + Math.cos(rad) * cp1Dist + Math.cos(perpRad) * cpWidth;
    const leftCp1Y = leftBaseY + Math.sin(rad) * cp1Dist + Math.sin(perpRad) * cpWidth;
    const leftCp2X = tipX + Math.cos(perpRad) * (cpWidth * 0.3);
    const leftCp2Y = tipY + Math.sin(perpRad) * (cpWidth * 0.3);

    const rightCp2X = tipX - Math.cos(perpRad) * (cpWidth * 0.3);
    const rightCp2Y = tipY - Math.sin(perpRad) * (cpWidth * 0.3);
    const rightCp1X = rightBaseX + Math.cos(rad) * cp1Dist - Math.cos(perpRad) * cpWidth;
    const rightCp1Y = rightBaseY + Math.sin(rad) * cp1Dist - Math.sin(perpRad) * cpWidth;

    return `M ${leftBaseX} ${leftBaseY} C ${leftCp1X} ${leftCp1Y}, ${leftCp2X} ${leftCp2Y}, ${tipX} ${tipY} C ${rightCp2X} ${rightCp2Y}, ${rightCp1X} ${rightCp1Y}, ${rightBaseX} ${rightBaseY} Z`;
  };

  const petalAngles = [0, 60, 120, 180, 240, 300];
  const petalGradients = [
    "petal1Gradient",
    "petal2Gradient",
    "petal3Gradient",
    "petal4Gradient",
    "petal5Gradient",
    "petal6Gradient",
  ];

  return (
    <AnimatedView style={[{ width: size, height: size }, animated ? animatedStyle : undefined]}>
      <Svg width={size} height={size} viewBox="0 0 100 100" fill="none">
        <Defs>
          <LinearGradient id="petal1Gradient" x1="50%" y1="100%" x2="50%" y2="0%">
            <Stop offset="0%" stopColor="#F9A8D4" />
            <Stop offset="100%" stopColor="#FBCFE8" />
          </LinearGradient>
          <LinearGradient id="petal2Gradient" x1="0%" y1="100%" x2="100%" y2="0%">
            <Stop offset="0%" stopColor="#F472B6" />
            <Stop offset="100%" stopColor="#F9A8D4" />
          </LinearGradient>
          <LinearGradient id="petal3Gradient" x1="0%" y1="50%" x2="100%" y2="50%">
            <Stop offset="0%" stopColor="#E879F9" />
            <Stop offset="100%" stopColor="#D946EF" />
          </LinearGradient>
          <LinearGradient id="petal4Gradient" x1="50%" y1="0%" x2="50%" y2="100%">
            <Stop offset="0%" stopColor="#C084FC" />
            <Stop offset="100%" stopColor="#A855F7" />
          </LinearGradient>
          <LinearGradient id="petal5Gradient" x1="100%" y1="0%" x2="0%" y2="100%">
            <Stop offset="0%" stopColor="#A855F7" />
            <Stop offset="100%" stopColor="#9333EA" />
          </LinearGradient>
          <LinearGradient id="petal6Gradient" x1="100%" y1="50%" x2="0%" y2="50%">
            <Stop offset="0%" stopColor="#DB2777" />
            <Stop offset="100%" stopColor="#EC4899" />
          </LinearGradient>
          <RadialGradient id="centerGradient" cx="40%" cy="40%" r="60%">
            <Stop offset="0%" stopColor="#FCD34D" />
            <Stop offset="100%" stopColor="#F59E0B" />
          </RadialGradient>
          <RadialGradient id="bgGradient" cx="50%" cy="50%" r="70%">
            <Stop offset="0%" stopColor="#FDF2F8" />
            <Stop offset="100%" stopColor="#FCE7F3" />
          </RadialGradient>
        </Defs>

        {showBackground ? (
          <Circle cx={centerX} cy={centerY} r={48} fill="url(#bgGradient)" />
        ) : null}

        <G>
          {petalAngles.map((angle, index) => (
            <Path
              key={index}
              d={createPetalPath(angle)}
              fill={`url(#${petalGradients[index]})`}
            />
          ))}

          <Circle cx={centerX} cy={centerY} r={10} fill="url(#centerGradient)" />
          <Circle cx={centerX - 2} cy={centerY - 2} r={3} fill="#FDE68A" opacity={0.7} />
        </G>
      </Svg>
    </AnimatedView>
  );
}

const styles = StyleSheet.create({
  container: {
    alignItems: "center",
    justifyContent: "center",
  },
});

