  focused: boolean;
}

function TabIcon({ name, color, focused }: TabIconProps) {
  const { isDark } = useTheme();

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [
        {
          translateY: withSpring(focused ? -2 : 0, {
            damping: 15,
            stiffness: 150,
          }),
        },
        {
          scale: withSpring(focused ? 1.1 : 1, {
            damping: 15,
            stiffness: 150,
          }),
        },
      ],
    };
  });

  const containerStyle = useAnimatedStyle(() => {
    return {
      backgroundColor: withSpring(
        focused
          ? isDark
            ? JasminColors.night.deep
            : JasminColors.brand.purple100
          : "transparent",
        { damping: 15, stiffness: 150 }
      ),
    };
  });

  return (
    <Animated.View
      style={[
        styles.iconContainer,
        containerStyle,
        animatedStyle,
      ]}
    >
      <Feather
        name={name}
        size={22}
        color={color}
        strokeWidth={focused ? 2.5 : 2}
      />
    </Animated.View>
  );
}

function DashboardStackNavigator() {
  const { theme, isDark } = useTheme();
  const commonOptions = getCommonScreenOptions({ theme, isDark });
  return (
    <DashboardStack.Navigator screenOptions={commonOptions}>
      <DashboardStack.Screen
