import { useSafeAreaInsets } from "react-native-safe-area-context";
import { useScreenInsets } from "@/hooks/useScreenInsets";

interface Store {
  id: string;
  name: string;
  address: string;
  district: string;
  city: string;
  phone: string;
  hours: string;
  isActive: boolean;
  latitude?: number;
  longitude?: number;
}

const RWANDA_DISTRICTS = [
  "Gasabo", "Kicukiro", "Nyarugenge",
  "Burera", "Gakenke", "Gicumbi", "Musanze", "Rulindo",
  "Bugesera", "Gatsibo", "Kayonza", "Kirehe", "Ngoma", "Nyagatare", "Rwamagana",
  "Gisagara", "Huye", "Kamonyi", "Muhanga", "Nyamagabe", "Nyanza", "Nyaruguru", "Ruhango",
  "Karongi", "Ngororero", "Nyabihu", "Nyamasheke", "Rubavu", "Rusizi", "Rutsiro",
];

const DEMO_STORES: Store[] = [
  {
    id: "1",
    name: "Jasmin Pharmacy - Kigali Center",
    address: "KN 5 Road, Kigali Heights",
    district: "Gasabo",
    city: "Kigali",
    phone: "+250 788 123 456",
    hours: "Mon-Sat: 8:00 AM - 9:00 PM",
    isActive: true,
    latitude: -1.9441,
    longitude: 30.0619,
  },
  {
    id: "2",
    name: "Jasmin Wellness Hub",
    address: "KG 11 Ave, Kimihurura",
    district: "Gasabo",
    city: "Kigali",
    phone: "+250 788 789 012",
    hours: "Mon-Fri: 9:00 AM - 6:00 PM",
    isActive: true,
    latitude: -1.9536,
    longitude: 30.0847,
  },
];

export default function MerchantStoresScreen() {
  const { theme, isDark } = useTheme();
  const { t } = useLanguage();
  const { tabBarHeight } = useScreenInsets();
  const insets = useSafeAreaInsets();

  const [stores, setStores] = useState<Store[]>(DEMO_STORES);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newStore, setNewStore] = useState({
    name: "",
    address: "",
    district: "Gasabo",
    city: "Kigali",
    phone: "",
    hours: "Mon-Sat: 8:00 AM - 6:00 PM",
  });

  const handleAddStore = () => {
    if (!newStore.name || !newStore.address) {
      const message = "Please fill in store name and address";
      if (Platform.OS === "web") {
        window.alert(message);
      } else {
        Alert.alert("Missing Information", message);
      }
      return;
    }

    const store: Store = {
      id: `new_${Date.now()}`,
      name: newStore.name,
      address: newStore.address,
      district: newStore.district,
      city: newStore.city,
      phone: newStore.phone,
      hours: newStore.hours,
      isActive: true,
    };

    setStores([store, ...stores]);
    setShowAddModal(false);
    setNewStore({
      name: "",
      address: "",
      district: "Gasabo",
      city: "Kigali",
      phone: "",
      hours: "Mon-Sat: 8:00 AM - 6:00 PM",
    });
  };

  const handleToggleActive = (storeId: string) => {
    setStores(stores.map((s) => 
      s.id === storeId ? { ...s, isActive: !s.isActive } : s
    ));
  };

  const handleDeleteStore = (storeId: string) => {
    const confirmDelete = () => {
      setStores(stores.filter((s) => s.id !== storeId));
    };

    if (Platform.OS === "web") {
      if (window.confirm("Are you sure you want to delete this store location?")) {
        confirmDelete();
      }
    } else {
      Alert.alert(
        "Delete Store",
        "Are you sure you want to delete this store location?",
        [
          { text: "Cancel", style: "cancel" },
          { text: "Delete", style: "destructive", onPress: confirmDelete },
        ]
      );
    }
  };

  const renderStore = ({ item }: { item: Store }) => (
    <GlassCard style={[styles.storeCard, !item.isActive && styles.inactiveCard]}>
      <View style={styles.storeHeader}>
        <View style={styles.storeIcon}>
          <Feather name="map-pin" size={20} color={JasminColors.maternal.teal600} />
        </View>
        <View style={styles.storeInfo}>
          <ThemedText style={styles.storeName}>{item.name}</ThemedText>
          <View style={styles.districtBadge}>
            <ThemedText style={styles.districtText}>{item.district}, {item.city}</ThemedText>
          </View>
        </View>
        <View style={[styles.statusIndicator, { backgroundColor: item.isActive ? JasminColors.maternal.emerald500 : JasminColors.gray[400] }]} />
      </View>

      <View style={styles.storeDetails}>
        <View style={styles.detailRow}>
          <Feather name="home" size={16} color={JasminColors.gray[400]} />
          <ThemedText style={styles.detailText}>{item.address}</ThemedText>
        </View>
        <View style={styles.detailRow}>
          <Feather name="clock" size={16} color={JasminColors.gray[400]} />
          <ThemedText style={styles.detailText}>{item.hours}</ThemedText>
        </View>
        <View style={styles.detailRow}>
          <Feather name="phone" size={16} color={JasminColors.gray[400]} />
          <ThemedText style={styles.detailText}>{item.phone}</ThemedText>
        </View>
      </View>

      <View style={styles.storeActions}>
        <Pressable 
          style={[styles.actionButton, styles.editButton]}
          onPress={() => {}}
        >
          <Feather name="edit-2" size={14} color={JasminColors.maternal.teal600} />
          <ThemedText style={[styles.actionButtonText, { color: JasminColors.maternal.teal600 }]}>
            Edit
          </ThemedText>
        </Pressable>
        <Pressable 
          style={[
            styles.actionButton, 
            item.isActive ? styles.deactivateButton : styles.activateButton
          ]}
          onPress={() => handleToggleActive(item.id)}
        >
          <Feather 
            name={item.isActive ? "eye-off" : "eye"} 
            size={14} 
            color={item.isActive ? JasminColors.gray[500] : JasminColors.maternal.emerald500} 
          />
          <ThemedText 
            style={[
              styles.actionButtonText, 
              { color: item.isActive ? JasminColors.gray[500] : JasminColors.maternal.emerald500 }
            ]}
          >
            {item.isActive ? "Close" : "Open"}
          </ThemedText>
        </Pressable>
        <Pressable 
          style={[styles.actionButton, styles.deleteButton]}
          onPress={() => handleDeleteStore(item.id)}
        >
          <Feather name="trash-2" size={14} color={JasminColors.phases.menstrual.primary} />
        </Pressable>
      </View>
    </GlassCard>
  );

  return (
    <ThemedView style={styles.container}>
      <View style={styles.headerStats}>
        <GlassCard style={styles.statCard}>
          <ThemedText style={styles.statValue}>{stores.length}</ThemedText>
          <ThemedText style={styles.statLabel}>Total Stores</ThemedText>
        </GlassCard>
        <GlassCard style={styles.statCard}>
          <ThemedText style={[styles.statValue, { color: JasminColors.maternal.emerald500 }]}>
            {stores.filter((s) => s.isActive).length}
          </ThemedText>
          <ThemedText style={styles.statLabel}>Active</ThemedText>
        </GlassCard>
        <GlassCard style={styles.statCard}>
          <ThemedText style={[styles.statValue, { color: JasminColors.gray[400] }]}>
            {stores.filter((s) => !s.isActive).length}
          </ThemedText>
          <ThemedText style={styles.statLabel}>Closed</ThemedText>
        </GlassCard>
      </View>

      <FlatList
        data={stores}
        keyExtractor={(item) => item.id}
        renderItem={renderStore}
        contentContainerStyle={[styles.storesList, { paddingBottom: tabBarHeight + Spacing.xl }]}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          <GlassCard style={styles.emptyCard}>
            <Feather name="map-pin" size={48} color={JasminColors.maternal.teal600} />
            <ThemedText style={styles.emptyTitle}>Your Stores</ThemedText>
            <ThemedText style={styles.emptyText}>
              Add store locations to manage inventory and accept orders
            </ThemedText>
          </GlassCard>
        }
      />

      <Pressable 
        style={[styles.fab, { bottom: tabBarHeight + Spacing.lg }]}
        onPress={() => setShowAddModal(true)}
      >
        <Feather name="plus" size={24} color="#FFFFFF" />
      </Pressable>

      <Modal
        visible={showAddModal}
        animationType="slide"
        transparent={true}
        onRequestClose={() => setShowAddModal(false)}
      >
        <View style={styles.modalOverlay}>
          <View style={[
            styles.modalContent, 
            { 
              backgroundColor: isDark ? JasminColors.night.deep : "#FFFFFF",
              paddingBottom: insets.bottom + Spacing.lg
            }
          ]}>
            <View style={styles.modalHeader}>
              <ThemedText style={styles.modalTitle}>Add Store Location</ThemedText>
              <Pressable onPress={() => setShowAddModal(false)}>
                <Feather name="x" size={24} color={JasminColors.gray[400]} />
              </Pressable>
            </View>

            <View style={styles.formGroup}>
              <ThemedText style={styles.label}>Store Name</ThemedText>
              <TextInput
                style={[
                  styles.input, 
                  { 
                    backgroundColor: isDark ? JasminColors.night.surface : JasminColors.gray[100],
                    color: isDark ? "#FFFFFF" : "#000000"
                  }
                ]}
                placeholder="e.g., Jasmin Pharmacy - Main Branch"
                placeholderTextColor={JasminColors.gray[400]}
                value={newStore.name}
                onChangeText={(text) => setNewStore({ ...newStore, name: text })}
              />
            </View>

            <View style={styles.formGroup}>
              <ThemedText style={styles.label}>Address</ThemedText>
