import { useTheme } from "@/hooks/useTheme";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";
import { SupportedLanguage } from "@/i18n";

interface LanguagePickerProps {
  onClose?: () => void;
}

export function LanguagePicker({ onClose }: LanguagePickerProps) {
  const { language, languages, setLanguage, t } = useLanguage();
  const { isDark } = useTheme();

  const handleSelectLanguage = async (code: SupportedLanguage) => {
    await setLanguage(code);
    onClose?.();
  };

  return (
    <View style={styles.container}>
      <ThemedText type="sectionHeader" style={styles.header}>
        {t("settings.selectLanguage")}
      </ThemedText>

      {languages.map((lang) => (
        <Pressable
          key={lang.code}
          onPress={() => handleSelectLanguage(lang.code)}
          style={({ pressed }) => [
            styles.languageItem,
            {
              backgroundColor: isDark 
                ? pressed ? JasminColors.night.surface : "transparent"
                : pressed ? JasminColors.gray[100] : "transparent",
            },
          ]}
        >
          <View style={styles.languageInfo}>
            <ThemedText type="body" style={styles.languageName}>
              {lang.nativeName}
            </ThemedText>
            <ThemedText type="small" style={styles.languageSubtitle}>
              {lang.name}
            </ThemedText>
          </View>

          {language === lang.code ? (
            <View style={styles.checkmark}>
              <Feather 
                name="check" 
                size={20} 
                color={JasminColors.brand.pink500} 
              />
            </View>
          ) : null}
        </Pressable>
      ))}
    </View>
  );
}

interface LanguageSettingRowProps {
  onPress: () => void;
}

export function LanguageSettingRow({ onPress }: LanguageSettingRowProps) {
  const { language, languages, t } = useLanguage();
  const { isDark } = useTheme();

  const currentLanguage = languages.find(l => l.code === language);

  return (
    <Pressable
      onPress={onPress}
      style={({ pressed }) => [
        styles.settingRow,
        {
          backgroundColor: isDark 
            ? pressed ? JasminColors.night.surface : JasminColors.night.deep
            : pressed ? JasminColors.gray[100] : "#FFFFFF",
        },
      ]}
    >
      <View style={styles.settingIcon}>
        <Feather name="globe" size={20} color={JasminColors.brand.purple500} />
      </View>
      <View style={styles.settingContent}>
        <ThemedText type="body">{t("settings.language")}</ThemedText>
