export default function AdminUsersScreen() {
  const { theme, isDark } = useTheme();
  const { t } = useLanguage();
  const [users, setUsers] = useState<User[]>(DEMO_USERS);
  const [roleFilter, setRoleFilter] = useState<RoleFilter>("All");
  const [searchQuery, setSearchQuery] = useState("");
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);

  const filteredUsers = users.filter((u) => {
    let matchesRole = true;
    if (roleFilter === "Users") matchesRole = u.role === "user";
    else if (roleFilter === "Merchants") matchesRole = u.role === "merchant";
    else if (roleFilter === "Admins") matchesRole = u.role === "admin";

    const matchesSearch = u.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         u.email.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesRole && matchesSearch;
  });

  const totalUsers = users.filter((u) => u.role === "user").length;
  const totalMerchants = users.filter((u) => u.role === "merchant").length;
  const totalActive = users.filter((u) => u.status === "active").length;

  const handleSuspend = (id: string) => {
    const user = users.find((u) => u.id === id);
    if (!user) return;

    const confirmAction = () => {
      setUsers((prev) =>
        prev.map((u) => (u.id === id ? { ...u, status: "suspended" as const } : u))
      );
    };

    if (Platform.OS === "web") {
      if (window.confirm(`Suspend ${user.name}? They will not be able to access the app.`)) {
        confirmAction();
      }
    } else {
      Alert.alert(
        "Suspend User",
        `Suspend ${user.name}? They will not be able to access the app.`,
        [
          { text: t("common.cancel"), style: "cancel" },
          { text: "Suspend", style: "destructive", onPress: confirmAction },
        ]
      );
    }
  };

  const handleReactivate = (id: string) => {
    const user = users.find((u) => u.id === id);
    if (!user) return;

    const confirmAction = () => {
      setUsers((prev) =>
        prev.map((u) => (u.id === id ? { ...u, status: "active" as const } : u))
      );
    };

    if (Platform.OS === "web") {
      if (window.confirm(`Reactivate ${user.name}?`)) {
        confirmAction();
      }
    } else {
      Alert.alert(
        "Reactivate User",
        `Reactivate ${user.name}?`,
        [
          { text: t("common.cancel"), style: "cancel" },
          { text: "Reactivate", onPress: confirmAction },
        ]
      );
    }
  };

  const onRefresh = () => {
    setRefreshing(true);
    setTimeout(() => setRefreshing(false), 1000);
  };

  const getRoleColor = (role: User["role"]) => {
    switch (role) {
      case "user": return JasminColors.brand.purple600;
      case "merchant": return JasminColors.maternal.teal600;
      case "admin": return JasminColors.phases.menstrual.primary;
    }
  };

  const getRoleBg = (role: User["role"]) => {
    switch (role) {
      case "user": return JasminColors.brand.purple100;
      case "merchant": return JasminColors.maternal.teal100;
      case "admin": return JasminColors.phases.menstrual.secondary;
    }
  };

  const getStatusIcon = (status: User["status"]) => {
    switch (status) {
      case "active": return "check-circle";
      case "inactive": return "clock";
      case "suspended": return "slash";
    }
  };

  const getStatusColor = (status: User["status"]) => {
    switch (status) {
      case "active": return JasminColors.maternal.emerald500;
      case "inactive": return JasminColors.gray[400];
      case "suspended": return JasminColors.phases.menstrual.primary;
    }
  };

  const renderUser = ({ item }: { item: User }) => {
    const isExpanded = expandedId === item.id;

    return (
      <GlassCard style={styles.userCard}>
        <Pressable onPress={() => setExpandedId(isExpanded ? null : item.id)}>
          <View style={styles.userHeader}>
            <View style={[styles.avatar, { backgroundColor: getRoleBg(item.role) }]}>
              <ThemedText style={[styles.avatarText, { color: getRoleColor(item.role) }]}>
                {item.name.charAt(0).toUpperCase()}
              </ThemedText>
            </View>
            <View style={styles.userInfo}>
              <View style={styles.userTitleRow}>
                <ThemedText style={styles.userName}>{item.name}</ThemedText>
                <Feather
                  name={getStatusIcon(item.status)}
                  size={14}
                  color={getStatusColor(item.status)}
                />
              </View>
              <ThemedText style={styles.userEmail}>{item.email}</ThemedText>
              <View style={[styles.roleBadge, { backgroundColor: getRoleBg(item.role) }]}>
                <ThemedText style={[styles.roleText, { color: getRoleColor(item.role) }]}>
                  {item.role.charAt(0).toUpperCase() + item.role.slice(1)}
                </ThemedText>
              </View>
            </View>
            <Feather
              name={isExpanded ? "chevron-up" : "chevron-down"}
              size={20}
              color={JasminColors.gray[400]}
            />
          </View>
        </Pressable>

        {isExpanded && (
          <View style={styles.userDetails}>
            <View style={styles.detailsGrid}>
              <View style={styles.detailItem}>
                <Feather name="calendar" size={14} color={JasminColors.gray[400]} />
                <ThemedText style={styles.detailText}>Joined {item.created_at}</ThemedText>
              </View>
              <View style={styles.detailItem}>
                <Feather name="clock" size={14} color={JasminColors.gray[400]} />
                <ThemedText style={styles.detailText}>Last active: {item.last_active}</ThemedText>
              </View>
            </View>

            {item.role === "user" && (
              <View style={styles.statsRow}>
                <View style={styles.statItem}>
                  <Feather name="activity" size={16} color={JasminColors.brand.purple600} />
                  <ThemedText style={styles.statValue}>{item.cycle_entries}</ThemedText>
                  <ThemedText style={styles.statLabel}>Cycle Entries</ThemedText>
                </View>
                <View style={styles.statItem}>
                  <Feather name="shopping-bag" size={16} color={JasminColors.maternal.teal600} />
                  <ThemedText style={styles.statValue}>{item.orders}</ThemedText>
                  <ThemedText style={styles.statLabel}>Orders</ThemedText>
                </View>
              </View>
            )}

            {item.role === "merchant" && (
              <View style={styles.statsRow}>
                <View style={styles.statItem}>
                  <Feather name="shopping-bag" size={16} color={JasminColors.maternal.teal600} />
                  <ThemedText style={styles.statValue}>{item.orders}</ThemedText>
                  <ThemedText style={styles.statLabel}>Total Orders</ThemedText>
                </View>
              </View>
            )}

            {item.role !== "admin" && (
              <View style={styles.actionButtons}>
                {item.status === "active" || item.status === "inactive" ? (
                  <Pressable
                    style={[styles.actionButtonOutline, { borderColor: JasminColors.phases.menstrual.primary }]}
                    onPress={() => handleSuspend(item.id)}
                  >
                    <Feather name="slash" size={16} color={JasminColors.phases.menstrual.primary} />
                    <ThemedText style={[styles.actionButtonText, { color: JasminColors.phases.menstrual.primary }]}>
                      Suspend
                    </ThemedText>
                  </Pressable>
                ) : (
                  <Pressable
                    style={[styles.actionButton, { backgroundColor: JasminColors.maternal.teal600 }]}
                    onPress={() => handleReactivate(item.id)}
                  >
                    <Feather name="refresh-cw" size={16} color="#FFFFFF" />
                    <ThemedText style={[styles.actionButtonText, { color: "#FFFFFF" }]}>
                      Reactivate
                    </ThemedText>
                  </Pressable>
                )}
              </View>
            )}
          </View>
        )}
      </GlassCard>
    );
  };

  return (
    <ThemedView style={styles.container}>
      <View style={styles.searchContainer}>
        <View style={[styles.searchBox, { backgroundColor: isDark ? JasminColors.night.surface : JasminColors.gray[100] }]}>
          <Feather name="search" size={18} color={JasminColors.gray[400]} />
          <TextInput
            style={[styles.searchInput, { color: isDark ? "#FFFFFF" : "#000000" }]}
            placeholder="Search users..."
            placeholderTextColor={JasminColors.gray[400]}
            value={searchQuery}
            onChangeText={setSearchQuery}
          />
        </View>
      </View>

      <View style={styles.statsRow}>
        <View style={[styles.statChip, { backgroundColor: JasminColors.brand.purple100 }]}>
          <ThemedText style={[styles.statChipValue, { color: JasminColors.brand.purple600 }]}>{totalUsers}</ThemedText>
          <ThemedText style={styles.statChipLabel}>Users</ThemedText>
        </View>
        <View style={[styles.statChip, { backgroundColor: JasminColors.maternal.teal100 }]}>
          <ThemedText style={[styles.statChipValue, { color: JasminColors.maternal.teal600 }]}>{totalMerchants}</ThemedText>
          <ThemedText style={styles.statChipLabel}>Merchants</ThemedText>
        </View>
        <View style={[styles.statChip, { backgroundColor: JasminColors.maternal.emerald100 }]}>
          <ThemedText style={[styles.statChipValue, { color: JasminColors.maternal.emerald500 }]}>{totalActive}</ThemedText>
          <ThemedText style={styles.statChipLabel}>Active</ThemedText>
        </View>
      </View>

      <View style={styles.filtersContainer}>
        <FlatList
          data={ROLE_FILTERS}
          horizontal
          showsHorizontalScrollIndicator={false}
          keyExtractor={(item) => item}
          contentContainerStyle={styles.filtersList}
          renderItem={({ item }) => (
            <Pressable
              style={[
                styles.filterChip,
                roleFilter === item && styles.filterChipActive,
              ]}
              onPress={() => setRoleFilter(item)}
            >
              <ThemedText
                style={[
                  styles.filterChipText,
                  roleFilter === item && styles.filterChipTextActive,
                ]}
              >
                {item}
              </ThemedText>
            </Pressable>
          )}
        />
      </View>

      <FlatList
        data={filteredUsers}
        keyExtractor={(item) => item.id}
        renderItem={renderUser}
        contentContainerStyle={styles.listContent}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} />
        }
        ListEmptyComponent={
          <GlassCard style={styles.emptyCard}>
            <Feather name="users" size={48} color={JasminColors.gray[400]} />
            <ThemedText style={styles.emptyText}>No users found</ThemedText>
          </GlassCard>
        }
      />
    </ThemedView>
  );
}

const styles = StyleSheet.create({
