import { JasminColors, Spacing, BorderRadius } from "@/constants/theme";

interface TimeRange {
  label: string;
  value: "7d" | "30d" | "90d" | "1y";
}

const TIME_RANGES: TimeRange[] = [
  { label: "7 Days", value: "7d" },
  { label: "30 Days", value: "30d" },
  { label: "90 Days", value: "90d" },
  { label: "1 Year", value: "1y" },
