        </GlassCard>
      </View>

      <View style={styles.section}>
        <ThemedText style={styles.sectionTitle}>Top Products</ThemedText>
        <GlassCard style={styles.tableCard}>
          {DEMO_TOP_PRODUCTS.map((product, index) => (
