import React, { useState } from "react";
import { View, StyleSheet, Pressable, TextInput, FlatList, Alert, Platform, Modal, ScrollView } from "react-native";
import { Feather } from "@expo/vector-icons";
import { Image } from "expo-image";
import * as ImagePicker from "expo-image-picker";
import { KeyboardAwareScrollView } from "react-native-keyboard-controller";

import { ThemedText } from "@/components/ThemedText";
import { ThemedView } from "@/components/ThemedView";
import { GlassCard } from "@/components/GlassCard";
import { Button } from "@/components/Button";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/context/AuthContext";
import { useLanguage } from "@/context/LanguageContext";
import { JasminColors, Spacing, BorderRadius } from "@/constants/theme";
import { productsApi } from "@/services/api";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { useScreenInsets } from "@/hooks/useScreenInsets";

interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  stock: number;
  category: string;
  imageUrl?: string;
  isActive: boolean;
}

const DEMO_PRODUCTS: Product[] = [
  {
    id: "1",
    name: "Prenatal Vitamins",
    description: "Essential vitamins for expectant mothers",
    price: 15000,
    stock: 50,
    category: "Supplements",
    isActive: true,
  },
  {
    id: "2",
    name: "Menstrual Cup - Size M",
    description: "Reusable menstrual cup, medical-grade silicone",
    price: 8000,
    stock: 25,
    category: "Hygiene",
    isActive: true,
  },
  {
    id: "3",
    name: "Organic Cotton Pads",
    description: "Pack of 10 organic cotton sanitary pads",
    price: 3500,
    stock: 100,
    category: "Hygiene",
    isActive: true,
  },
  {
    id: "4",
    name: "Folic Acid Supplement",
    description: "400mcg daily folic acid tablets - 90 count",
    price: 12000,
    stock: 0,
    category: "Supplements",
    isActive: false,
  },
];

const CATEGORIES = ["All", "Hygiene", "Supplements", "Maternal Care", "Wellness"];

export default function MerchantProductsScreen() {
  const { theme, isDark } = useTheme();
  const { user } = useAuth();
  const { t } = useLanguage();
  const { tabBarHeight } = useScreenInsets();
  const insets = useSafeAreaInsets();

  const [products, setProducts] = useState<Product[]>(DEMO_PRODUCTS);
  const [loading, setLoading] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [searchQuery, setSearchQuery] = useState("");
  const [showAddModal, setShowAddModal] = useState(false);
  const [newProduct, setNewProduct] = useState({
    name: "",
    description: "",
    price: "",
    stock: "",
    category: "Hygiene",
    imageUri: "",
  });

  const handlePickImage = async () => {
    if (Platform.OS === "web") {
      const result = await ImagePicker.launchImageLibraryAsync({
        mediaTypes: ["images"],
        allowsEditing: true,
        aspect: [1, 1],
        quality: 0.8,
      });

      if (!result.canceled && result.assets[0]) {
        setNewProduct({ ...newProduct, imageUri: result.assets[0].uri });
      }
      return;
    }

    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();

    if (status !== "granted") {
      Alert.alert(
        t("common.error"),
        "Please enable photo library access in Settings to add product images.",
        [{ text: t("common.ok") }]
      );
      return;
    }

    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ["images"],
      allowsEditing: true,
      aspect: [1, 1],
      quality: 0.8,
    });

    if (!result.canceled && result.assets[0]) {
      setNewProduct({ ...newProduct, imageUri: result.assets[0].uri });
    }
  };

  const filteredProducts = products.filter((product) => {
    const matchesCategory = selectedCategory === "All" || product.category === selectedCategory;
    const matchesSearch = product.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const formatCurrency = (amount: number) => `${amount.toLocaleString()} RWF`;

  const getStockColor = (stock: number) => {
    if (stock === 0) return JasminColors.gray[400];
    if (stock < 10) return JasminColors.phases.menstrual.primary;
    if (stock < 25) return JasminColors.phases.luteal.primary;
    return JasminColors.maternal.emerald500;
  };

  const handleAddProduct = () => {
    if (!newProduct.name || !newProduct.price) {
      const message = "Please fill in product name and price";
      if (Platform.OS === "web") {
        window.alert(message);
      } else {
        Alert.alert("Missing Information", message);
      }
      return;
    }

    const product: Product = {
      id: `new_${Date.now()}`,
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price) || 0,
      stock: parseInt(newProduct.stock) || 0,
      category: newProduct.category,
      isActive: true,
    };

    setProducts([product, ...products]);
    setShowAddModal(false);
    setNewProduct({ name: "", description: "", price: "", stock: "", category: "Hygiene", imageUri: "" });
  };

  const handleToggleActive = (productId: string) => {
    setProducts(products.map((p) => 
      p.id === productId ? { ...p, isActive: !p.isActive } : p
    ));
  };

  const handleDeleteProduct = (productId: string) => {
    const confirmDelete = () => {
      setProducts(products.filter((p) => p.id !== productId));
    };

    if (Platform.OS === "web") {
      if (window.confirm("Are you sure you want to delete this product?")) {
        confirmDelete();
      }
    } else {
      Alert.alert(
        "Delete Product",
        "Are you sure you want to delete this product?",
        [
          { text: "Cancel", style: "cancel" },
          { text: "Delete", style: "destructive", onPress: confirmDelete },
        ]
      );
    }
  };

  const renderProduct = ({ item }: { item: Product }) => (
    <GlassCard style={[styles.productCard, !item.isActive && styles.inactiveCard]}>
      <View style={styles.productHeader}>
        <View style={styles.productImagePlaceholder}>
          <Feather name="package" size={24} color={JasminColors.maternal.teal600} />
        </View>
        <View style={styles.productInfo}>
          <ThemedText style={styles.productName}>{item.name}</ThemedText>
          <ThemedText style={styles.productCategory}>{item.category}</ThemedText>
        </View>
        <Pressable 
          style={styles.menuButton}
          onPress={() => handleDeleteProduct(item.id)}
        >
          <Feather name="trash-2" size={18} color={JasminColors.gray[400]} />
