components/BrandedBackground.tsx.content:
import React from "react";
import { View, StyleSheet, useColorScheme, Image, Dimensions } from "react-native";
import { LinearGradient } from "expo-linear-gradient";
import { DeepLavender } from "@/constants/theme";

interface BrandedBackgroundProps {
  children: React.ReactNode;
  variant?: "default" | "subtle" | "prominent";
  showLogo?: boolean;
  style?: object;
}

const { width: screenWidth } = Dimensions.get("window");

export function BrandedBackground({
  children,
  variant = "default",
  showLogo = true,
  style,
}: BrandedBackgroundProps) {
  const colorScheme = useColorScheme();
  const isDark = colorScheme === "dark";

  const getGradientColors = (): readonly [string, string, ...string[]] => {
    if (isDark) {
      switch (variant) {
        case "subtle":
          return [DeepLavender.base, DeepLavender.surface];
        case "prominent":
          return [DeepLavender.deep, DeepLavender.base, DeepLavender.surface];
        default:
          return [DeepLavender.base, DeepLavender.surface];
      }
    } else {
      switch (variant) {
        case "subtle":
          return ["#FFFFFF", "#FDF2F8"];
        case "prominent":
          return ["#FCE7F3", "#FDF2F8", "#FFFFFF"];
        default:
          return ["#FDF2F8", "#FFFFFF"];
      }
    }
  };

  const logoOpacity = isDark ? 0.03 : 0.05;

  return (
    <View style={[styles.container, style]}>
      <LinearGradient
        colors={getGradientColors()}
        style={StyleSheet.absoluteFillObject}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 1 }}
      />

      {showLogo ? (
        <View style={styles.logoContainer} pointerEvents="none">
          <Image
            source={require("../assets/images/icon.png")}
            style={[
              styles.logoWatermark,
              { opacity: logoOpacity }
            ]}
            resizeMode="contain"
          />
        </View>
      ) : null}

      {children}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  logoContainer: {
    ...StyleSheet.absoluteFillObject,
    justifyContent: "center",
    alignItems: "center",
    zIndex: 0,
  },
  logoWatermark: {
    width: screenWidth * 0.8,
    height: screenWidth * 0.8,
    maxWidth: 400,
    maxHeight: 400,
  },
});

