export function formatRWF(amount: number): string {
  const rounded = Math.round(amount);
  const formatted = rounded.toLocaleString("en-US");
  return `${formatted} RWF`;
}

export function formatRWFCompact(amount: number): string {
  if (amount >= 1000000) {
    return `${(amount / 1000000).toFixed(1)}M RWF`;
  }
  if (amount >= 1000) {
    return `${(amount / 1000).toFixed(0)}K RWF`;
  }
  return formatRWF(amount);
}

components/AIChatModal.tsx.content:
import React, { useState, useRef, useEffect } from "react";
import {
  View,
  StyleSheet,
  Modal,
  Pressable,
  TextInput,
  FlatList,
  KeyboardAvoidingView,
  Platform,
  Dimensions,
} from "react-native";
import { BlurView } from "expo-blur";
import { LinearGradient } from "expo-linear-gradient";
import { Feather } from "@expo/vector-icons";
import Animated, {
  FadeIn,
  FadeInDown,
  FadeOut,
  SlideInDown,
  SlideOutDown,
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withRepeat,
  withSequence,
  withTiming,
} from "react-native-reanimated";
import { useSafeAreaInsets } from "react-native-safe-area-context";

import { ThemedText } from "@/components/ThemedText";
import { JasminBrandIcon } from "@/components/JasminBrandIcon";
import { useTheme } from "@/hooks/useTheme";
import { useLanguage } from "@/context/LanguageContext";
import { JasminColors, Spacing, BorderRadius } from "@/constants/theme";

const { height: SCREEN_HEIGHT } = Dimensions.get("window");

interface Message {
  id: string;
  text: string;
  sender: "user" | "jasmin";
  timestamp: Date;
}

interface AIChatModalProps {
  visible: boolean;
  onClose: () => void;
}

const JASMIN_RESPONSES = [
  "I'm here to support you on your wellness journey. How can I help today?",
  "That's a great question! Based on your cycle phase, I'd recommend focusing on gentle self-care activities.",
  "I understand. It's completely normal to feel that way during this phase. Your body is doing amazing work!",
  "Remember, every cycle is unique. Would you like me to suggest some wellness tips tailored to how you're feeling?",
  "You're doing wonderfully! Taking time to check in with yourself is an important step in self-care.",
  "I'm so glad you reached out. Let me share some insights that might help you feel more comfortable.",
  "Based on what you've shared, it sounds like your body might benefit from some extra rest. Shall I suggest some calming activities?",
  "That's a wonderful observation! Tracking these patterns helps you understand your body better over time.",
];

const SUGGESTED_QUESTIONS = [
  "What phase am I in?",
  "Why do I feel tired?",
  "Suggest self-care tips",
  "What foods should I eat?",
];

export function AIChatModal({ visible, onClose }: AIChatModalProps) {
  const { isDark } = useTheme();
  const { t } = useLanguage();
  const insets = useSafeAreaInsets();
  const [messages, setMessages] = useState<Message[]>([
    {
      id: "welcome",
      text: "Hi! I'm Jasmin, your personal wellness companion. I'm here to help you understand your body and support your cycle journey. What would you like to know?",
      sender: "jasmin",
      timestamp: new Date(),
    },
  ]);
  const [inputText, setInputText] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const flatListRef = useRef<FlatList>(null);

  const typingDot1 = useSharedValue(0.3);
  const typingDot2 = useSharedValue(0.3);
  const typingDot3 = useSharedValue(0.3);

  useEffect(() => {
    if (isTyping) {
      typingDot1.value = withRepeat(
        withSequence(
          withTiming(1, { duration: 300 }),
          withTiming(0.3, { duration: 300 })
        ),
        -1
      );
      typingDot2.value = withRepeat(
        withSequence(
          withTiming(0.3, { duration: 150 }),
          withTiming(1, { duration: 300 }),
          withTiming(0.3, { duration: 300 })
        ),
        -1
      );
      typingDot3.value = withRepeat(
        withSequence(
          withTiming(0.3, { duration: 300 }),
          withTiming(1, { duration: 300 }),
          withTiming(0.3, { duration: 150 })
        ),
        -1
      );
    }
  }, [isTyping]);

  const dot1Style = useAnimatedStyle(() => ({ opacity: typingDot1.value }));
  const dot2Style = useAnimatedStyle(() => ({ opacity: typingDot2.value }));
  const dot3Style = useAnimatedStyle(() => ({ opacity: typingDot3.value }));

  const handleSend = async (text?: string) => {
    const messageText = text || inputText.trim();
    if (!messageText) return;

    const userMessage: Message = {
      id: `user_${Date.now()}`,
      text: messageText,
      sender: "user",
      timestamp: new Date(),
    };

    setMessages((prev) => [...prev, userMessage]);
    setInputText("");
    setIsTyping(true);

    setTimeout(() => {
      flatListRef.current?.scrollToEnd({ animated: true });
    }, 100);

    await new Promise((resolve) => setTimeout(resolve, 1500 + Math.random() * 1000));

    const jasminResponse: Message = {
      id: `jasmin_${Date.now()}`,
      text: JASMIN_RESPONSES[Math.floor(Math.random() * JASMIN_RESPONSES.length)],
      sender: "jasmin",
      timestamp: new Date(),
    };

    setIsTyping(false);
    setMessages((prev) => [...prev, jasminResponse]);

    setTimeout(() => {
      flatListRef.current?.scrollToEnd({ animated: true });
    }, 100);
  };

  const renderMessage = ({ item, index }: { item: Message; index: number }) => {
    const isUser = item.sender === "user";

    return (
      <Animated.View
        entering={FadeInDown.delay(index * 50).duration(300)}
        style={[
          styles.messageContainer,
          isUser ? styles.userMessageContainer : styles.jasminMessageContainer,
        ]}
      >
        {!isUser ? (
          <View style={styles.avatarContainer}>
            <LinearGradient
              colors={[JasminColors.brand.purple500, JasminColors.brand.purple600]}
              style={styles.avatar}
            >
              <JasminBrandIcon size={20} />
            </LinearGradient>
          </View>
        ) : null}

        <View
          style={[
            styles.messageBubble,
            isUser ? styles.userBubble : styles.jasminBubble,
          ]}
        >
          <ThemedText
            style={[
              styles.messageText,
              isUser ? styles.userText : styles.jasminText,
            ]}
          >
            {item.text}
          </ThemedText>
          <ThemedText style={styles.timestamp}>
            {item.timestamp.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}
          </ThemedText>
        </View>
      </Animated.View>
    );
  };

  const renderTypingIndicator = () => {
    if (!isTyping) return null;

    return (
      <Animated.View
        entering={FadeIn.duration(200)}
        exiting={FadeOut.duration(200)}
        style={[styles.messageContainer, styles.jasminMessageContainer]}
      >
        <View style={styles.avatarContainer}>
          <LinearGradient
            colors={[JasminColors.brand.purple500, JasminColors.brand.purple600]}
            style={styles.avatar}
          >
            <JasminBrandIcon size={20} animated animationType="pulse" />
          </LinearGradient>
        </View>
        <View style={[styles.messageBubble, styles.jasminBubble, styles.typingBubble]}>
          <View style={styles.typingDots}>
            <Animated.View style={[styles.typingDot, dot1Style]} />
            <Animated.View style={[styles.typingDot, dot2Style]} />
            <Animated.View style={[styles.typingDot, dot3Style]} />
          </View>
        </View>
      </Animated.View>
    );
  };

  const bgColor = isDark ? JasminColors.night.base : "#FFFFFF";
  const headerBg = isDark ? JasminColors.night.surface : JasminColors.gray[50];
  const inputBg = isDark ? JasminColors.night.deep : JasminColors.gray[100];

  return (
    <Modal
      visible={visible}
      animationType="none"
      transparent
      onRequestClose={onClose}
    >
      <Animated.View
        entering={SlideInDown.springify().damping(15)}
        exiting={SlideOutDown.duration(300)}
        style={[styles.container, { backgroundColor: bgColor }]}
      >
        <LinearGradient
          colors={[JasminColors.brand.purple500, JasminColors.brand.purple600]}
          style={[styles.header, { paddingTop: insets.top + Spacing.md }]}
        >
          <View style={styles.headerContent}>
            <View style={styles.headerLeft}>
              <View style={styles.headerAvatar}>
                <JasminBrandIcon size={28} animated animationType="pulse" />
              </View>
              <View>
                <ThemedText style={styles.headerTitle}>Jasmin AI</ThemedText>
                <ThemedText style={styles.headerSubtitle}>Your Wellness Companion</ThemedText>
              </View>
            </View>
            <Pressable style={styles.closeButton} onPress={onClose}>
              <Feather name="x" size={24} color="#FFFFFF" />
            </Pressable>
          </View>
        </LinearGradient>

        <View style={styles.suggestionsContainer}>
          <FlatList
            data={SUGGESTED_QUESTIONS}
            horizontal
            showsHorizontalScrollIndicator={false}
            keyExtractor={(item) => item}
            contentContainerStyle={styles.suggestionsList}
            renderItem={({ item }) => (
              <Pressable
                style={[styles.suggestionChip, { borderColor: JasminColors.brand.purple400 }]}
                onPress={() => handleSend(item)}
              >
                <ThemedText style={styles.suggestionText}>{item}</ThemedText>
              </Pressable>
            )}
          />
        </View>

        <FlatList
          ref={flatListRef}
          data={messages}
          keyExtractor={(item) => item.id}
          renderItem={renderMessage}
          contentContainerStyle={styles.messagesList}
          ListFooterComponent={renderTypingIndicator}
          showsVerticalScrollIndicator={false}
        />

        <KeyboardAvoidingView
          behavior={Platform.OS === "ios" ? "padding" : "height"}
          keyboardVerticalOffset={0}
        >
          <View
            style={[
              styles.inputContainer,
              { paddingBottom: insets.bottom + Spacing.md, backgroundColor: headerBg },
            ]}
          >
            <View style={[styles.inputWrapper, { backgroundColor: inputBg }]}>
              <TextInput
                style={[styles.input, { color: isDark ? "#FFFFFF" : "#000000" }]}
                placeholder="Ask Jasmin anything..."
                placeholderTextColor={JasminColors.gray[400]}
                value={inputText}
                onChangeText={setInputText}
                multiline
                maxLength={500}
              />
              <Pressable
                style={[
                  styles.sendButton,
                  !inputText.trim() && styles.sendButtonDisabled,
                ]}
                onPress={() => handleSend()}
                disabled={!inputText.trim() || isTyping}
              >
                <LinearGradient
                  colors={
                    inputText.trim()
                      ? [JasminColors.brand.purple500, JasminColors.brand.purple600]
                      : [JasminColors.gray[300], JasminColors.gray[400]]
                  }
                  style={styles.sendButtonGradient}
                >
                  <Feather name="send" size={18} color="#FFFFFF" />
                </LinearGradient>
              </Pressable>
            </View>
          </View>
        </KeyboardAvoidingView>
      </Animated.View>
    </Modal>
  );
}

