import React, { useState, useEffect, useCallback } from "react";
import { View, StyleSheet, Pressable, Platform, TextInput, Dimensions, Alert } from "react-native";
import { Feather } from "@expo/vector-icons";
import * as LocalAuthentication from "expo-local-authentication";
import * as Haptics from "expo-haptics";
import Animated, {
  FadeIn,
  FadeOut,
  useSharedValue,
  useAnimatedStyle,
  withSpring,
  withSequence,
} from "react-native-reanimated";
import { LinearGradient } from "expo-linear-gradient";
import { useSafeAreaInsets } from "react-native-safe-area-context";

import { ThemedText } from "@/components/ThemedText";
import { JasminBrandIcon } from "@/components/JasminBrandIcon";
import { useTheme } from "@/hooks/useTheme";
import { storage } from "@/services/storage";
import { Spacing, BorderRadius, JasminColors } from "@/constants/theme";

const SPACING_XXL = Spacing["2xl"];

const { width } = Dimensions.get("window");

interface AppLockScreenProps {
  onUnlock: () => void;
  visible: boolean;
}

const PIN_LENGTH = 4;

export function AppLockScreen({ onUnlock, visible }: AppLockScreenProps) {
  const { isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const [pin, setPin] = useState("");
  const [error, setError] = useState("");
  const [biometricType, setBiometricType] = useState<string>("Biometric");
  const [biometricAvailable, setBiometricAvailable] = useState(false);
  const [showPinEntry, setShowPinEntry] = useState(false);
  const shakeX = useSharedValue(0);

  useEffect(() => {
    if (visible) {
      checkBiometricSupport();
    }
  }, [visible]);

  const checkBiometricSupport = async () => {
    if (Platform.OS === "web") {
      setShowPinEntry(true);
      setBiometricAvailable(false);
      return;
    }

    const hasHardware = await LocalAuthentication.hasHardwareAsync();
    const isEnrolled = await LocalAuthentication.isEnrolledAsync();
    const biometricEnabled = await storage.isBiometricEnabled();

    if (hasHardware && isEnrolled && biometricEnabled) {
      const types = await LocalAuthentication.supportedAuthenticationTypesAsync();
      if (types.includes(LocalAuthentication.AuthenticationType.FACIAL_RECOGNITION)) {
        setBiometricType("Face ID");
      } else if (types.includes(LocalAuthentication.AuthenticationType.FINGERPRINT)) {
        setBiometricType("Touch ID");
      }
      setBiometricAvailable(true);
      attemptBiometricAuth();
    } else {
      setShowPinEntry(true);
      setBiometricAvailable(false);
    }
  };

  const attemptBiometricAuth = async () => {
    try {
      const result = await LocalAuthentication.authenticateAsync({
        promptMessage: "Unlock Jasmin",
        disableDeviceFallback: true,
        cancelLabel: "Use PIN",
      });

      if (result.success) {
        if (Platform.OS !== "web") {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        }
        onUnlock();
      } else {
        setShowPinEntry(true);
      }
    } catch (error) {
      setShowPinEntry(true);
    }
  };

  const handlePinPress = useCallback(async (digit: string) => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }

    const newPin = pin + digit;
    setPin(newPin);
    setError("");

    if (newPin.length === PIN_LENGTH) {
      const savedPin = await storage.getAppPin();
      if (savedPin && newPin === savedPin) {
        if (Platform.OS !== "web") {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        }
        onUnlock();
      } else if (!savedPin) {
        await storage.setAppPin(newPin);
        if (Platform.OS !== "web") {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        }
        onUnlock();
      } else {
        if (Platform.OS !== "web") {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
        }
        shakeX.value = withSequence(
          withSpring(-10, { damping: 2, stiffness: 500 }),
          withSpring(10, { damping: 2, stiffness: 500 }),
          withSpring(-10, { damping: 2, stiffness: 500 }),
          withSpring(0, { damping: 2, stiffness: 500 })
        );
        setError("Incorrect PIN");
        setPin("");
      }
    }
  }, [pin, onUnlock, shakeX]);

  const handleDelete = useCallback(() => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setPin((prev) => prev.slice(0, -1));
    setError("");
  }, []);

  const animatedPinStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: shakeX.value }],
  }));

  if (!visible) return null;

  const backgroundColor = isDark ? JasminColors.night.base : "#FFFFFF";

  return (
    <Animated.View
      entering={FadeIn.duration(200)}
      exiting={FadeOut.duration(200)}
      style={[styles.container, { backgroundColor }]}
    >
      <View style={[styles.content, { paddingTop: insets.top + SPACING_XXL }]}>
        <View style={styles.logoContainer}>
          <LinearGradient
            colors={[JasminColors.brand.pink500, JasminColors.brand.purple600]}
            style={styles.logoGradient}
          >
            <JasminBrandIcon size={48} />
          </LinearGradient>
          <ThemedText type="h2" style={styles.title}>
            Jasmin
          </ThemedText>
          <ThemedText style={styles.subtitle}>
            {showPinEntry ? "Enter your PIN to unlock" : `Use ${biometricType} to unlock`}
          </ThemedText>
        </View>

        {showPinEntry ? (
          <View style={styles.pinSection}>
            <Animated.View style={[styles.pinDots, animatedPinStyle]}>
              {Array.from({ length: PIN_LENGTH }).map((_, index) => (
                <View
                  key={index}
                  style={[
                    styles.pinDot,
                    {
                      backgroundColor:
                        index < pin.length
                          ? JasminColors.brand.pink500
                          : isDark
                            ? JasminColors.night.surface
                            : JasminColors.gray[200],
                    },
                  ]}
                />
              ))}
            </Animated.View>

            {error ? (
              <ThemedText style={styles.error}>{error}</ThemedText>
            ) : null}

            <View style={styles.keypad}>
              {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((digit) => (
                <Pressable
                  key={digit}
                  onPress={() => handlePinPress(digit.toString())}
                  style={({ pressed }) => [
                    styles.keypadButton,
                    {
                      backgroundColor: pressed
                        ? isDark
                          ? JasminColors.night.deep
                          : JasminColors.gray[100]
                        : isDark
                          ? JasminColors.night.surface
                          : JasminColors.gray[50],
                    },
                  ]}
                >
                  <ThemedText style={styles.keypadText}>{digit}</ThemedText>
                </Pressable>
              ))}
              {biometricAvailable ? (
                <Pressable
                  onPress={attemptBiometricAuth}
                  style={({ pressed }) => [
                    styles.keypadButton,
                    {
                      backgroundColor: pressed
                        ? isDark
                          ? JasminColors.night.deep
                          : JasminColors.gray[100]
                        : "transparent",
                    },
                  ]}
                >
                  <Feather
                    name={biometricType === "Face ID" ? "smile" : "smartphone"}
                    size={24}
                    color={JasminColors.brand.pink500}
                  />
                </Pressable>
              ) : (
                <View style={styles.keypadButton} />
              )}
              <Pressable
                onPress={() => handlePinPress("0")}
                style={({ pressed }) => [
                  styles.keypadButton,
                  {
                    backgroundColor: pressed
                      ? isDark
                        ? JasminColors.night.deep
                        : JasminColors.gray[100]
                      : isDark
                        ? JasminColors.night.surface
                        : JasminColors.gray[50],
                  },
                ]}
              >
                <ThemedText style={styles.keypadText}>0</ThemedText>
              </Pressable>
              <Pressable
                onPress={handleDelete}
                style={({ pressed }) => [
                  styles.keypadButton,
                  {
                    backgroundColor: pressed
                      ? isDark
                        ? JasminColors.night.deep
                        : JasminColors.gray[100]
                      : "transparent",
                  },
                ]}
              >
                <Feather
                  name="delete"
                  size={24}
                  color={isDark ? JasminColors.gray[400] : JasminColors.gray[600]}
                />
              </Pressable>
            </View>
          </View>
        ) : (
          <View style={styles.biometricSection}>
            <Pressable
              onPress={attemptBiometricAuth}
              style={({ pressed }) => [
                styles.biometricButton,
                {
                  backgroundColor: pressed
                    ? isDark
                      ? JasminColors.night.deep
                      : JasminColors.gray[100]
                    : isDark
                      ? JasminColors.night.surface
                      : JasminColors.gray[50],
                },
              ]}
            >
              <Feather
                name={biometricType === "Face ID" ? "smile" : "smartphone"}
                size={48}
                color={JasminColors.brand.pink500}
              />
              <ThemedText style={styles.biometricText}>
                Tap to use {biometricType}
              </ThemedText>
            </Pressable>

            <Pressable onPress={() => setShowPinEntry(true)}>
              <ThemedText style={styles.usePinLink}>Use PIN instead</ThemedText>
            </Pressable>
          </View>
        )}
      </View>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: {
    ...StyleSheet.absoluteFillObject,
    zIndex: 1000,
  },
  content: {
    flex: 1,
    paddingHorizontal: Spacing.xl,
  },
  logoContainer: {
    alignItems: "center",
    marginBottom: SPACING_XXL,
  },
  logoGradient: {
    width: 80,
