  },
  keypadText: {
    fontSize: 28,
    fontWeight: "500",
  },
  biometricSection: {
    alignItems: "center",
    marginTop: SPACING_XXL,
  },
  biometricButton: {
    width: 120,
    height: 120,
    borderRadius: 60,
    alignItems: "center",
