import React from "react";
import MapView, { Marker, PROVIDER_DEFAULT, type Region, type MapMarkerProps } from "react-native-maps";

export { PROVIDER_DEFAULT };
export type { Region, MapMarkerProps };

export interface MapViewWrapperProps {
  region: Region;
  onRegionChangeComplete?: (region: Region) => void;
  showsUserLocation?: boolean;
  children?: React.ReactNode;
  style?: any;
  mapRef?: React.RefObject<MapView>;
}

export function MapViewWrapper({
  region,
  onRegionChangeComplete,
  showsUserLocation = false,
  children,
  style,
  mapRef,
}: MapViewWrapperProps) {
  return (
    <MapView
      ref={mapRef}
      style={style}
      initialRegion={region}
      onRegionChangeComplete={onRegionChangeComplete}
      showsUserLocation={showsUserLocation}
      provider={PROVIDER_DEFAULT}
    >
      {children}
    </MapView>
  );
}

export interface MarkerWrapperProps {
  coordinate: {
    latitude: number;
    longitude: number;
  };
  title?: string;
  description?: string;
  onPress?: () => void;
  pinColor?: string;
  children?: React.ReactNode;
}

export function MarkerWrapper({
  coordinate,
  title,
  description,
  onPress,
  pinColor,
  children,
}: MarkerWrapperProps) {
  return (
    <Marker
      coordinate={coordinate}
      title={title}
      description={description}
      onPress={onPress}
      pinColor={pinColor}
    >
      {children}
    </Marker>
  );
}

export const isMapAvailable = true;

context/DiscreetModeContext.tsx.content:
import React, { createContext, useContext, useState, useEffect, useCallback, ReactNode } from "react";
import { Platform } from "react-native";
import * as Haptics from "expo-haptics";
import { storage } from "@/services/storage";

interface DiscreetModeContextType {
  isDiscreetMode: boolean;
  toggleDiscreetMode: () => void;
  enableDiscreetMode: () => void;
  disableDiscreetMode: () => void;
}

const DiscreetModeContext = createContext<DiscreetModeContextType | undefined>(undefined);

interface DiscreetModeProviderProps {
  children: ReactNode;
}

export function DiscreetModeProvider({ children }: DiscreetModeProviderProps) {
  const [isDiscreetMode, setIsDiscreetMode] = useState(false);

  useEffect(() => {
    loadDiscreetModeSetting();
  }, []);

  const loadDiscreetModeSetting = async () => {
    try {
      const enabled = await storage.isDiscreetModeEnabled();
      setIsDiscreetMode(enabled);
    } catch (error) {
      console.error("Error loading discreet mode setting:", error);
    }
  };

  const toggleDiscreetMode = useCallback(async () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }
    const newValue = !isDiscreetMode;
    setIsDiscreetMode(newValue);
    await storage.setDiscreetModeEnabled(newValue);
  }, [isDiscreetMode]);

  const enableDiscreetMode = useCallback(async () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Heavy);
    }
    setIsDiscreetMode(true);
    await storage.setDiscreetModeEnabled(true);
  }, []);

  const disableDiscreetMode = useCallback(async () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setIsDiscreetMode(false);
    await storage.setDiscreetModeEnabled(false);
  }, []);

  return (
    <DiscreetModeContext.Provider
      value={{
        isDiscreetMode,
        toggleDiscreetMode,
        enableDiscreetMode,
        disableDiscreetMode,
      }}
    >
      {children}
    </DiscreetModeContext.Provider>
  );
}

export function useDiscreetMode(): DiscreetModeContextType {
  const context = useContext(DiscreetModeContext);
  if (!context) {
    throw new Error("useDiscreetMode must be used within a DiscreetModeProvider");
  }
  return context;
}

components/CycleCalendar.tsx.content:
import React, { useMemo } from "react";
import { View, StyleSheet, Pressable, Platform } from "react-native";
import { BlurView } from "expo-blur";
import Animated, {
  useAnimatedStyle,
  withSpring,
  useSharedValue,
} from "react-native-reanimated";

import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import {
  JasminColors,
  Spacing,
  BorderRadius,
  CyclePhase,
  Shadows,
} from "@/constants/theme";
import { getPhaseForDay } from "@/services/cycleService";

interface CycleCalendarProps {
  currentDay: number;
  totalDays: number;
  periodLength?: number;
  cycleStartDate: Date;
  selectedDay: number | null;
  onDaySelect: (day: number) => void;
  loggedDays?: number[];
}

interface DayCellProps {
  day: number;
  cycleDay: number | null;
  phase: CyclePhase | null;
  isToday: boolean;
  isSelected: boolean;
  hasLog: boolean;
  isDark: boolean;
  isOvulationDay: boolean;
  onPress: () => void;
}

const CELL_SIZE = 40;
const PHASE_DOT_SIZE = 28;
const WEEKDAYS = ["S", "M", "T", "W", "T", "F", "S"];

const AnimatedPressable = Animated.createAnimatedComponent(Pressable);

function DayCell({
  day,
  cycleDay,
  phase,
  isToday,
  isSelected,
  hasLog,
  isDark,
  isOvulationDay,
  onPress,
}: DayCellProps) {
  const scale = useSharedValue(1);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ scale: scale.value }],
  }));

  const handlePressIn = () => {
    scale.value = withSpring(0.95, { damping: 15, stiffness: 300 });
  };

  const handlePressOut = () => {
    scale.value = withSpring(isSelected ? 1.1 : 1, { damping: 15, stiffness: 300 });
  };

  const getPhaseColor = () => {
    if (!phase) return "transparent";
    switch (phase) {
      case "menstrual":
        return isDark ? JasminColors.brand.pink500 : JasminColors.brand.pink300;
      case "follicular":
        return isDark ? JasminColors.brand.teal700 : JasminColors.brand.teal200;
      case "ovulation":
        return isDark ? JasminColors.brand.purple500 : JasminColors.brand.purple400;
      case "luteal":
        return isDark ? JasminColors.brand.slate400 : JasminColors.gray[300];
      default:
        return "transparent";
    }
  };

  const getTextColor = () => {
    if (isSelected) {
      return isDark ? JasminColors.gray[900] : "#FFFFFF";
    }
    if (isToday) {
      return isDark ? JasminColors.brand.pink300 : JasminColors.brand.pink500;
    }
    return isDark ? JasminColors.gray[300] : JasminColors.gray[700];
  };

  return (
    <AnimatedPressable
      style={[
        styles.dayCell,
        animatedStyle,
        isSelected && [
          styles.dayCellSelected,
          {
            backgroundColor: isDark ? "#FFFFFF" : JasminColors.gray[800],
          },
        ],
      ]}
      onPress={onPress}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
    >
      {isToday && !isSelected ? (
        <View
          style={[
            styles.todayRing,
            { borderColor: JasminColors.brand.pink300 },
          ]}
        />
      ) : null}

      {!isSelected && phase ? (
        <View
          style={[
            styles.phaseIndicator,
            {
              backgroundColor: getPhaseColor(),
            },
            isOvulationDay && styles.ovulationIndicator,
          ]}
        />
      ) : null}

      <ThemedText
        style={[
          styles.dayText,
          { color: getTextColor() },
          isToday && !isSelected && styles.dayTextToday,
        ]}
      >
        {day}
      </ThemedText>

      {hasLog ? (
        <View
          style={[
            styles.logDot,
            {
              backgroundColor: isSelected
                ? isDark
                  ? JasminColors.brand.pink500
                  : JasminColors.brand.pink300
                : JasminColors.brand.pink500,
            },
          ]}
        />
      ) : null}
    </AnimatedPressable>
  );
}

export function CycleCalendar({
  currentDay,
  totalDays,
  periodLength = 5,
  cycleStartDate,
  selectedDay,
  onDaySelect,
  loggedDays = [],
}: CycleCalendarProps) {
  const { isDark } = useTheme();

  const today = new Date();
  const currentMonth = today.getMonth();
  const currentYear = today.getFullYear();
  const todayDate = today.getDate();

  const { calendarDays, weeks } = useMemo(() => {
    const startOfMonth = new Date(currentYear, currentMonth, 1);
    const endOfMonth = new Date(currentYear, currentMonth + 1, 0);
    const startDayOfWeek = startOfMonth.getDay();
    const daysInMonth = endOfMonth.getDate();

    const days: (number | null)[] = [];

    for (let i = 0; i < startDayOfWeek; i++) {
      days.push(null);
    }

    for (let i = 1; i <= daysInMonth; i++) {
      days.push(i);
    }

    while (days.length % 7 !== 0) {
      days.push(null);
    }

    const weekRows: (number | null)[][] = [];
    for (let i = 0; i < days.length; i += 7) {
      weekRows.push(days.slice(i, i + 7));
    }

    return { calendarDays: days, weeks: weekRows };
  }, [currentMonth, currentYear]);

  const getCycleDayForCalendarDay = (calendarDay: number): number | null => {
    const cycleStart = new Date(cycleStartDate);
    const targetDate = new Date(currentYear, currentMonth, calendarDay);

    const diffTime = targetDate.getTime() - cycleStart.getTime();
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return null;

    const cycleDay = (diffDays % totalDays) + 1;
    return cycleDay;
  };

  const isOvulationDayInCurrentCycle = (
    calendarDay: number,
    year: number,
    month: number,
    startDate: Date,
    cycleLen: number
  ): boolean => {
    const cycleStart = new Date(startDate);
    const targetDate = new Date(year, month, calendarDay);
    const exactOvulationCycleDay = Math.round(cycleLen / 2);

    const diffTime = targetDate.getTime() - cycleStart.getTime();
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays < 0) return false;

    const cycleNumber = Math.floor(diffDays / cycleLen);
    const ovulationDate = new Date(cycleStart);
    ovulationDate.setDate(ovulationDate.getDate() + (cycleNumber * cycleLen) + (exactOvulationCycleDay - 1));

    return (
      ovulationDate.getFullYear() === year &&
      ovulationDate.getMonth() === month &&
      ovulationDate.getDate() === calendarDay
    );
  };

  const monthName = new Date(currentYear, currentMonth).toLocaleDateString("en-US", {
    month: "long",
    year: "numeric",
  });

  return (
    <View
      style={[
        styles.container,
        {
          backgroundColor: isDark
            ? "rgba(26, 16, 37, 0.6)"
            : "#FFFFFF",
          borderColor: isDark
            ? "rgba(255, 255, 255, 0.05)"
            : JasminColors.gray[100],
        },
      ]}
    >
      {isDark && Platform.OS !== "web" ? (
        <BlurView intensity={20} style={StyleSheet.absoluteFill} />
      ) : null}

      <ThemedText style={styles.monthTitle}>{monthName}</ThemedText>

      <View style={styles.weekdayHeader}>
        {WEEKDAYS.map((day, index) => (
          <View key={index} style={styles.weekdayCell}>
            <ThemedText
              style={[
                styles.weekdayText,
                { color: isDark ? JasminColors.gray[400] : JasminColors.gray[500] },
              ]}
            >
              {day}
            </ThemedText>
          </View>
        ))}
      </View>

      {weeks.map((week, weekIndex) => (
        <View key={weekIndex} style={styles.weekRow}>
          {week.map((day, dayIndex) => {
            if (day === null) {
              return <View key={dayIndex} style={styles.emptyCell} />;
            }

            const cycleDay = getCycleDayForCalendarDay(day);
            const phase = cycleDay ? getPhaseForDay(cycleDay, totalDays, periodLength) : null;
            const isToday = day === todayDate;
            const isSelected = day === selectedDay;
            const hasLog = loggedDays.includes(day);

            const exactOvulationCycleDay = Math.round(totalDays / 2);
            const isOvulationDay = cycleDay !== null && cycleDay === exactOvulationCycleDay && isOvulationDayInCurrentCycle(day, currentYear, currentMonth, cycleStartDate, totalDays);

            return (
              <DayCell
                key={dayIndex}
                day={day}
                cycleDay={cycleDay}
                isOvulationDay={isOvulationDay}
                phase={phase}
                isToday={isToday}
                isSelected={isSelected}
                hasLog={hasLog}
                isDark={isDark}
                onPress={() => onDaySelect(day)}
              />
            );
          })}
        </View>
      ))}

      <View style={styles.legend}>
        <LegendItem color={JasminColors.brand.pink300} label="Menstrual" isDark={isDark} />
        <LegendItem color={JasminColors.brand.teal400} label="Follicular" isDark={isDark} />
        <LegendItem color={JasminColors.brand.purple400} label="Ovulation" isDark={isDark} />
        <LegendItem color={JasminColors.gray[400]} label="Luteal" isDark={isDark} />
      </View>
    </View>
  );
}

function LegendItem({ color, label, isDark }: { color: string; label: string; isDark: boolean }) {
  return (
    <View style={styles.legendItem}>
      <View style={[styles.legendDot, { backgroundColor: color }]} />
      <ThemedText style={[styles.legendText, { color: isDark ? JasminColors.gray[400] : JasminColors.gray[600] }]}>
        {label}
      </ThemedText>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    borderRadius: BorderRadius.lg,
    padding: Spacing.lg,
    borderWidth: 1,
    overflow: "hidden",
  },
  monthTitle: {
    fontSize: 18,
    fontWeight: "600",
    marginBottom: Spacing.md,
  },
  weekdayHeader: {
    flexDirection: "row",
    marginBottom: Spacing.sm,
  },
  weekdayCell: {
    width: CELL_SIZE,
    height: 24,
    alignItems: "center",
    justifyContent: "center",
  },
  weekdayText: {
    fontSize: 10,
    fontWeight: "600",
    textTransform: "uppercase",
    letterSpacing: 0.5,
  },
  weekRow: {
    flexDirection: "row",
    marginBottom: Spacing.xs,
  },
  emptyCell: {
    width: CELL_SIZE,
    height: CELL_SIZE,
  },
  dayCell: {
    width: CELL_SIZE,
    height: CELL_SIZE,
    borderRadius: CELL_SIZE / 2,
    alignItems: "center",
    justifyContent: "center",
    position: "relative",
  },
  dayCellSelected: {
    transform: [{ scale: 1.1 }],
    ...Shadows.lg,
  },
  todayRing: {
    position: "absolute",
    width: CELL_SIZE - 2,
    height: CELL_SIZE - 2,
    borderRadius: (CELL_SIZE - 2) / 2,
    borderWidth: 1,
  },
  phaseIndicator: {
    position: "absolute",
    width: PHASE_DOT_SIZE,
    height: PHASE_DOT_SIZE,
    borderRadius: PHASE_DOT_SIZE / 2,
    opacity: 0.5,
  },
  ovulationIndicator: {
    borderWidth: 1,
    borderColor: "#FFFFFF",
  },
  dayText: {
    fontSize: 12,
    fontWeight: "500",
    zIndex: 1,
  },
  dayTextToday: {
    fontWeight: "700",
  },
  logDot: {
    position: "absolute",
    bottom: 4,
    width: 4,
    height: 4,
    borderRadius: 2,
  },
  legend: {
    flexDirection: "row",
    flexWrap: "wrap",
    justifyContent: "center",
    gap: Spacing.md,
    marginTop: Spacing.lg,
    paddingTop: Spacing.md,
    borderTopWidth: StyleSheet.hairlineWidth,
    borderTopColor: "rgba(0,0,0,0.1)",
  },
  legendItem: {
    flexDirection: "row",
    alignItems: "center",
  },
  legendDot: {
    width: 8,
    height: 8,
    borderRadius: 4,
    marginRight: Spacing.xs,
  },
  legendText: {
    fontSize: 11,
  },
});
